import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Slide {
  id: string;
  title: string;
  content: string[];
  speakerNotes: string;
}

export interface Presentation {
  title: string;
  description: string;
  slides: Slide[];
}

export interface AppItem {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: string;
  url: string;
  color: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "../types";

export const generatePresentation = async (topic: string, style: string): Promise<Presentation> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Tạo một bài thuyết trình chuyên nghiệp về chủ đề: "${topic}". Phong cách: ${style}. Hãy viết bằng Tiếng Việt.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          slides: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                content: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                speakerNotes: { type: Type.STRING }
              },
              required: ["id", "title", "content", "speakerNotes"]
            }
          }
        },
        required: ["title", "description", "slides"]
      }
    }
  });

  if (!response.text) {
    throw new Error("Không thể tạo nội dung bài thuyết trình.");
  }

  return JSON.parse(response.text.trim());
};

