const PresentationCreator: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [style, setStyle] = useState('Professional');
  const [loading, setLoading] = useState(false);
  const [presentation, setPresentation] = useState<Presentation | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await generatePresentation(topic, style);
      setPresentation(data);
    } catch (err) {
      setError('Đã xảy ra lỗi khi tạo bài thuyết trình. Vui lòng thử lại.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 animate-in slide-in-from-bottom-4 duration-700">
      <section className="text-center space-y-4">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-100 text-indigo-700 text-xs font-bold uppercase tracking-wider">
          <i className="fa-solid fa-sparkles"></i> AI Powered
        </div>
        <h1 className="text-4xl font-extrabold text-gray-900 sm:text-5xl">Studio Thuyết Trình</h1>
        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
          Nhập chủ đề của bạn và AI của chúng tôi sẽ phác thảo toàn bộ bài thuyết trình bao gồm nội dung và ghi chú chỉ trong vài giây.
        </p>
      </section>

      <section className="bg-white p-8 rounded-3xl border border-gray-200 shadow-xl">
        <form onSubmit={handleGenerate} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="md:col-span-2 space-y-2">
              <label className="block text-sm font-bold text-gray-700">Chủ đề bài thuyết trình</label>
              <input
                type="text"
                placeholder="Ví dụ: Tương lai của Năng lượng Mặt trời..."
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                disabled={loading}
              />
            </div>
            <div className="space-y-2">
              <label className="block text-sm font-bold text-gray-700">Phong cách</label>
              <select
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none appearance-none"
                value={style}
                onChange={(e) => setStyle(e.target.value)}
                disabled={loading}
              >
                <option value="Professional">Chuyên nghiệp</option>
                <option value="Creative">Sáng tạo</option>
                <option value="Minimalist">Tối giản</option>
                <option value="Educational">Giáo dục</option>
              </select>
            </div>
          </div>

          <button
            type="submit"
            disabled={loading || !topic}
            className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all flex items-center justify-center gap-2 ${
              loading || !topic 
                ? 'bg-gray-300 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-200 active:scale-[0.98]'
            }`}
          >
            {loading ? (
              <>
                <i className="fa-solid fa-circle-notch animate-spin"></i>
                Đang tạo nội dung...
              </>
            ) : (
              <>
                <i className="fa-solid fa-wand-magic-sparkles"></i>
                Tạo bài thuyết trình ngay
              </>
            )}
          </button>
        </form>
      </section>

      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-xl text-red-600 flex items-center gap-3">
          <i className="fa-solid fa-circle-exclamation"></i>
          {error}
        </div>
      )}

      {presentation && (
        <div className="space-y-10 animate-in fade-in zoom-in-95 duration-500">
          <div className="border-l-4 border-indigo-600 pl-6 space-y-2">
            <h2 className="text-3xl font-bold text-gray-900">{presentation.title}</h2>
            <p className="text-gray-500">{presentation.description}</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {presentation.slides.map((slide, index) => (
              <SlideCard key={slide.id} slide={slide} index={index} />
            ))}
          </div>

          <div className="flex justify-center pt-8">
            <button 
              onClick={() => window.print()}
              className="px-6 py-3 bg-white border border-gray-200 rounded-xl font-bold text-gray-600 hover:bg-gray-50 transition-all flex items-center gap-2"
            >
              <i className="fa-solid fa-file-pdf"></i> Xuất ra PDF
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default PresentationCreator;

{
  "name": "TIG Hub & Presentation Studio",
  "description": "A professional dashboard to manage your applications and an AI-powered studio to generate stunning presentations in seconds.",
  "requestFramePermissions": []
}

export interface Slide {
  id: string;
  title: string;
  content: string[];
  speakerNotes: string;
  imageUrl?: string;
}

export interface Presentation {
  title: string;
  description: string;
  slides: Slide[];
}

export interface AppItem {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: string;
  url: string;
  color: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "../types";

export const generatePresentation = async (topic: string, style: string): Promise<Presentation> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Tạo một bài thuyết trình chuyên nghiệp về chủ đề: "${topic}". Phong cách: ${style}. Hãy viết bằng Tiếng Việt. Đảm bảo nội dung chi tiết và súc tích.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          slides: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                content: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                speakerNotes: { type: Type.STRING }
              },
              required: ["id", "title", "content", "speakerNotes"]
            }
          }
        },
        required: ["title", "description", "slides"]
      }
    }
  });

  if (!response.text) {
    throw new Error("Không thể tạo nội dung bài thuyết trình.");
  }

  return JSON.parse(response.text.trim());
};

export const generateImageForSlide = async (slideTitle: string, context: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `A professional, high-quality presentation visual for a slide titled "${slideTitle}". Context: ${context}. Style: minimalist, corporate, clean, 4k. No text in the image.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
  });

  for (const part of response.candidates?.[0].content.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Không thể tạo hình ảnh cho slide.");
};

