import React, { useState } from 'react';
import { generatePresentation, generateImageForSlide } from '../services/geminiService';
import { Presentation, Slide } from '../types';

const SlideCard: React.FC<{ slide: Slide; index: number; onUpdateImage: (url: string) => void }> = ({ slide, index, onUpdateImage }) => {
  const [generatingImage, setGeneratingImage] = useState(false);

  const handleGenerateImage = async () => {
    setGeneratingImage(true);
    try {
      const imageUrl = await generateImageForSlide(slide.title, slide.content.join(' '));
      onUpdateImage(imageUrl);
    } catch (err) {
      console.error(err);
      alert('Không thể tạo hình ảnh cho slide này.');
    } finally {
      setGeneratingImage(false);
    }
  };

  return (
    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden flex flex-col h-full transition-all hover:shadow-md print-break">
      <div className="p-4 bg-gray-50 border-b border-gray-200 flex items-center justify-between no-print">
        <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Slide {index + 1}</span>
        <button 
          onClick={handleGenerateImage}
          disabled={generatingImage}
          className={`text-xs font-bold px-3 py-1.5 rounded-lg border transition-all flex items-center gap-2 ${
            generatingImage 
              ? 'bg-gray-100 text-gray-400 border-gray-200' 
              : 'bg-white text-indigo-600 border-indigo-100 hover:bg-indigo-50 hover:border-indigo-200'
          }`}
        >
          {generatingImage ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-image"></i>}
          {slide.imageUrl ? 'Tạo lại hình ảnh' : 'Tạo hình ảnh AI'}
        </button>
      </div>

      <div className="flex flex-col md:flex-row h-full">
        {slide.imageUrl && (
          <div className="w-full md:w-1/3 border-b md:border-b-0 md:border-r border-gray-100">
            <img 
              src={slide.imageUrl} 
              alt={slide.title} 
              className="w-full h-48 md:h-full object-cover"
            />
          </div>
        )}
        <div className={`p-8 flex-1 flex flex-col justify-center ${slide.imageUrl ? 'md:w-2/3' : 'w-full'}`}>
          <h3 className="text-2xl font-extrabold text-gray-900 mb-6 leading-tight">{slide.title}</h3>
          <ul className="space-y-4">
            {slide.content.map((item, i) => (
              <li key={i} className="flex items-start gap-3 text-gray-700">
                <span className="mt-2 w-2 h-2 rounded-full bg-indigo-500 shrink-0"></span>
                <span className="text-lg leading-relaxed">{item}</span>
              </li>
            ))}
          </ul>
        </div>
      </div>

      <div className="p-4 bg-indigo-50 border-t border-indigo-100 no-print">
        <div className="flex items-center gap-2 text-xs font-bold text-indigo-400 uppercase tracking-widest mb-2">
          <i className="fa-solid fa-microphone"></i> Ghi chú người thuyết trình
        </div>
        <p className="text-sm text-indigo-800 italic leading-relaxed">"{slide.speakerNotes}"</p>
      </div>
    </div>
  );
};

const PresentationCreator: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [style, setStyle] = useState('Professional');
  const [loading, setLoading] = useState(false);
  const [presentation, setPresentation] = useState<Presentation | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await generatePresentation(topic, style);
      setPresentation(data);
    } catch (err) {
      setError('Đã xảy ra lỗi khi tạo bài thuyết trình. Vui lòng thử lại.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const updateSlideImage = (index: number, url: string) => {
    if (!presentation) return;
    const newSlides = [...presentation.slides];
    newSlides[index] = { ...newSlides[index], imageUrl: url };
    setPresentation({ ...presentation, slides: newSlides });
  };

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-in slide-in-from-bottom-4 duration-700">
      <section className="text-center space-y-4 no-print">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-100 text-indigo-700 text-xs font-bold uppercase tracking-wider">
          <i className="fa-solid fa-sparkles"></i> AI Studio
        </div>
        <h1 className="text-4xl font-extrabold text-gray-900 sm:text-5xl">Phòng Lab Thuyết Trình</h1>
        <p className="text-xl text-gray-500 max-w-2xl mx-auto">
          Biến ý tưởng thành bài thuyết trình hoàn chỉnh với nội dung, hình ảnh và ghi chú chỉ trong một cú nhấp chuột.
        </p>
      </section>

      <section className="bg-white p-8 rounded-3xl border border-gray-200 shadow-xl no-print">
        <form onSubmit={handleGenerate} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="md:col-span-2 space-y-2">
              <label className="block text-sm font-bold text-gray-700">Chủ đề bài thuyết trình</label>
              <input
                type="text"
                placeholder="Ví dụ: Tương lai của AI trong giáo dục..."
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                disabled={loading}
              />
            </div>
            <div className="space-y-2">
              <label className="block text-sm font-bold text-gray-700">Phong cách</label>
              <select
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 transition-all outline-none appearance-none"
                value={style}
                onChange={(e) => setStyle(e.target.value)}
                disabled={loading}
              >
                <option value="Professional">Chuyên nghiệp</option>
                <option value="Creative">Sáng tạo</option>
                <option value="Minimalist">Tối giản</option>
                <option value="Educational">Giáo dục</option>
              </select>
            </div>
          </div>

          <button
            type="submit"
            disabled={loading || !topic}
            className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all flex items-center justify-center gap-2 ${
              loading || !topic 
                ? 'bg-gray-300 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-200 active:scale-[0.98]'
            }`}
          >
            {loading ? (
              <>
                <i className="fa-solid fa-circle-notch animate-spin"></i>
                Đang thiết kế bài viết...
              </>
            ) : (
              <>
                <i className="fa-solid fa-wand-magic-sparkles"></i>
                Tạo bài thuyết trình ngay
              </>
            )}
          </button>
        </form>
      </section>

      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-xl text-red-600 flex items-center gap-3 no-print">
          <i className="fa-solid fa-circle-exclamation"></i>
          {error}
        </div>
      )}

      {presentation && (
        <div className="space-y-12 animate-in fade-in zoom-in-95 duration-500 pb-20">
          <div className="border-l-4 border-indigo-600 pl-6 space-y-2">
            <h2 className="text-4xl font-extrabold text-gray-900">{presentation.title}</h2>
            <p className="text-xl text-gray-500">{presentation.description}</p>
          </div>

          <div className="space-y-8">
            {presentation.slides.map((slide, index) => (
              <SlideCard 
                key={slide.id} 
                slide={slide} 
                index={index} 
                onUpdateImage={(url) => updateSlideImage(index, url)} 
              />
            ))}
          </div>

          <div className="flex justify-center pt-8 no-print">
            <button 
              onClick={() => window.print()}
              className="px-8 py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-xl hover:shadow-indigo-100 flex items-center gap-2"
            >
              <i className="fa-solid fa-file-export"></i> Xuất / In bài thuyết trình
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default PresentationCreator;

