const Dashboard: React.FC = () => {
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);

  // Load custom apps from localStorage
  useEffect(() => {
    const stored = localStorage.getItem('tig_hub_custom_apps');
    if (stored) {
      try {
        setCustomApps(JSON.parse(stored));
      } catch (e) {
        console.error("Failed to parse custom apps", e);
      }
    }
  }, []);

  const handleAddApp = (newApp: AppItem) => {
    const updated = [...customApps, newApp];
    setCustomApps(updated);
    localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
  };

  const handleDeleteApp = (id: string) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa ứng dụng này?')) {
      const updated = customApps.filter(app => app.id !== id);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
    }
  };

  const allApps = [...APPS, ...customApps];

  const filteredApps = allApps.filter(app => 
    app.name.toLowerCase().includes(search.toLowerCase()) ||
    app.category.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <section className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">TIG Hub</h1>
          <p className="text-gray-500 max-w-lg">
            Chào mừng trở lại! Đây là không gian làm việc tập trung cho tất cả các ứng dụng và công cụ của bạn.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-1 sm:w-80">
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input
              type="text"
              placeholder="Tìm kiếm ứng dụng..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none"
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
          >
            <i className="fa-solid fa-plus"></i>
            Đăng tải ứng dụng
          </button>
        </div>
      </section>

      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredApps.map((app) => (
          <AppCard 
            key={app.id} 
            app={app} 
            isCustom={customApps.some(ca => ca.id === app.id)}
            onDelete={handleDeleteApp}
          />
        ))}

        {filteredApps.length === 0 && (
          <div className="col-span-full py-20 text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-400">
              <i className="fa-solid fa-search text-2xl"></i>
            </div>
            <p className="text-gray-500 font-medium">Không tìm thấy ứng dụng nào phù hợp.</p>
          </div>
        )}
      </section>

      <AddAppModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onAdd={handleAddApp} 
      />
    </div>
  );
};

