import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "../types";

export const generatePresentation = async (topic: string, style: string): Promise<Presentation> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Tạo một bài thuyết trình chuyên nghiệp và sâu sắc về chủ đề: "${topic}". Phong cách: ${style}. Hãy viết bằng Tiếng Việt. Đảm bảo nội dung có cấu trúc logic, chi tiết và súc tích, phù hợp với xu hướng năm 2025.`,
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 4096 },
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          slides: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                content: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                speakerNotes: { type: Type.STRING }
              },
              required: ["id", "title", "content", "speakerNotes"]
            }
          }
        },
        required: ["title", "description", "slides"]
      }
    }
  });

  if (!response.text) {
    throw new Error("Không thể tạo nội dung bài thuyết trình.");
  }

  return JSON.parse(response.text.trim());
};

export const generateImageForSlide = async (slideTitle: string, context: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `A 2025-style, ultra-modern presentation visual for a slide titled "${slideTitle}". Context: ${context}. Aesthetics: glassmorphism, soft gradients, high-tech, futuristic but clean. 8k resolution. No text.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
  });

  for (const part of response.candidates?.[0].content.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Không thể tạo hình ảnh cho slide.");
};

