const Dashboard: React.FC = () => {
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);
  const [recentPresentations, setRecentPresentations] = useState<Presentation[]>([]);

  useEffect(() => {
    const storedApps = localStorage.getItem('tig_hub_custom_apps');
    if (storedApps) try { setCustomApps(JSON.parse(storedApps)); } catch (e) {}

    const storedPresentations = localStorage.getItem('tig_hub_presentations');
    if (storedPresentations) try { setRecentPresentations(JSON.parse(storedPresentations)); } catch (e) {}
  }, []);

  const handleAddApp = (newApp: AppItem) => {
    const updated = [newApp, ...customApps];
    setCustomApps(updated);
    localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
  };

  const handleDeleteApp = (id: string) => {
    if (window.confirm('Confirm deletion?')) {
      const updated = customApps.filter(app => app.id !== id);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
    }
  };

  const handleDeletePresentation = (id: string) => {
    if (window.confirm('Delete this presentation project?')) {
      const updated = recentPresentations.filter((p: any) => p.id !== id);
      setRecentPresentations(updated);
      localStorage.setItem('tig_hub_presentations', JSON.stringify(updated));
    }
  };

  const userContent = [
    ...recentPresentations.map((p: any) => ({ ...p, isPresentation: true })),
    ...customApps.map(a => ({ ...a, isCustom: true }))
  ];

  const displayApps = userContent.length > 0 ? [...userContent, ...APPS] : APPS;

  const filteredApps = displayApps.filter(app => {
    const name = app.name || app.title || '';
    const category = app.category || (app.isPresentation ? 'Presentation' : '') || '';
    return name.toLowerCase().includes(search.toLowerCase()) ||
           category.toLowerCase().includes(search.toLowerCase());
  });

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <section className="flex flex-col md:flex-row md:items-end justify-between gap-8 border-b border-gray-100 pb-12">
        <div className="space-y-4">
          <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-black text-white text-[9px] font-black uppercase tracking-widest">
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
            System Status: Active
          </div>
          <h1 className="text-5xl font-black text-gray-900 tracking-tighter">PROJECTS & TOOLS</h1>
          <p className="text-gray-500 max-w-lg font-medium">
            Truy cập nhanh vào các ứng dụng công nghệ và những bài thuyết trình AI mới nhất của bạn.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-1 sm:w-80 group">
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-black transition-colors"></i>
            <input
              type="text"
              placeholder="Search assets..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-4 bg-gray-100 border-none rounded-2xl focus:ring-2 focus:ring-black transition-all outline-none font-bold text-sm"
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="px-8 py-4 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-indigo-600 transition-all shadow-2xl active:scale-95"
          >
            <i className="fa-solid fa-plus text-xs"></i>
            Register Tool
          </button>
        </div>
      </section>

      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredApps.map((app: any, idx) => (
          <AppCard 
            key={app.id || idx} 
            app={app} 
            isCustom={app.isCustom}
            isPresentation={app.isPresentation}
            onDelete={app.isPresentation ? handleDeletePresentation : handleDeleteApp}
          />
        ))}
      </section>

      {filteredApps.length === 0 && (
        <div className="py-24 text-center space-y-4">
          <div className="w-20 h-20 bg-gray-100 rounded-[2rem] flex items-center justify-center mx-auto text-gray-300">
            <i className="fa-solid fa-ghost text-3xl"></i>
          </div>
          <p className="text-gray-400 font-black uppercase text-xs tracking-widest">No matching sectors found</p>
        </div>
      )}

      <AddAppModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onAdd={handleAddApp} 
      />
    </div>
  );
};

export default Dashboard;

