          <div className={`w-full max-w-lg rounded-[2.5rem] border shadow-2xl overflow-hidden animate-in zoom-in-95 ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-200'}`}>
            <div className="p-8 border-b border-white/5 flex items-center justify-between">
              <h2 className={`text-xl font-black uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Establish Sector</h2>
              <button onClick={() => setShowGroupModal(false)} className="text-gray-500 hover:text-white transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Group Name</label>
                <input 
                  id="groupName"
                  className={`w-full px-5 py-4 rounded-2xl outline-none border transition-all ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200 text-gray-900'}`}
                  placeholder="e.g. JavaScript Wizards"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Mission Objective</label>
                <textarea 
                  id="groupDesc"
                  className={`w-full px-5 py-4 rounded-2xl outline-none border transition-all resize-none ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200 text-gray-900'}`}
                  placeholder="What is this community for?"
                  rows={3}
                />
              </div>
              <button 
                onClick={() => {
                  const n = (document.getElementById('groupName') as HTMLInputElement).value;
                  const d = (document.getElementById('groupDesc') as HTMLTextAreaElement).value;
                  if(n && d) handleCreateGroup(n, d);
                }}
                className="w-full py-4 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-xl"
              >
                Initialize Community
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Community;

export interface Slide {
  id: string;
  title: string;
  content: string[];
  speakerNotes: string;
  imageUrl?: string;
}

export interface Presentation {
  title: string;
  description: string;
  slides: Slide[];
}

export interface AppItem {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: string;
  url: string;
  color: string;
}

export interface User {
  username: string;
  password?: string;
  name: string;
}

// Community Types
export interface CommunityComment {
  id: string;
  author: string;
  content: string;
  mediaUrl?: string;
  mediaType?: 'image' | 'audio';
  timestamp: string;
}

export interface CommunityPost {
  id: string;
  author: string;
  authorUsername: string;
  content: string;
  mediaUrl?: string;
  mediaType?: 'image' | 'audio';
  likes: number;
  comments: CommunityComment[];
  timestamp: string;
  groupId?: string;
}

export interface CommunityGroup {
  id: string;
  name: string;
  description: string;
  creator: string;
  memberCount: number;
  icon: string;
  color: string;
  isMember?: boolean;
}

export interface DirectMessage {
  id: string;
  sender: string;
  receiver?: string; // Dùng cho DM
  groupId?: string;  // Dùng cho Group Chat
  content: string;
  mediaUrl?: string;
  mediaType?: 'image' | 'audio';
  timestamp: string;
}

export interface FriendRelation {
  username: string;
  status: 'friend' | 'pending';
}

import React, { useState, useEffect } from 'react';
import { User, CommunityPost, CommunityGroup, DirectMessage, CommunityComment } from '../types';

const Community: React.FC<{ isDarkMode: boolean; user: User }> = ({ isDarkMode, user }) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'groups' | 'people' | 'messages'>('feed');
  const [posts, setPosts] = useState<CommunityPost[]>([]);
  const [groups, setGroups] = useState<CommunityGroup[]>([]);
  const [messages, setMessages] = useState<DirectMessage[]>([]);
  const [friends, setFriends] = useState<string[]>([]);
  const [users, setUsers] = useState<User[]>([]);

  // States for Search
  const [feedSearch, setFeedSearch] = useState('');
  const [groupSearch, setGroupSearch] = useState('');
  const [peopleSearch, setPeopleSearch] = useState('');

  // States for Group Detail & Chat
  const [viewingGroup, setViewingGroup] = useState<CommunityGroup | null>(null);
  const [groupChatMsg, setGroupChatMsg] = useState('');

  const [newPostContent, setNewPostContent] = useState('');
  const [mediaFile, setMediaFile] = useState<{url: string, type: 'image' | 'audio'} | null>(null);
  const [showGroupModal, setShowGroupModal] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<string | null>(null);

  // Load Data
  useEffect(() => {
    const savedPosts = localStorage.getItem('tig_community_posts');
    const savedGroups = localStorage.getItem('tig_community_groups');
    const savedMessages = localStorage.getItem('tig_community_messages');
    const savedFriends = localStorage.getItem(`tig_friends_${user.username}`);
    const registeredUsers = JSON.parse(localStorage.getItem('tig_hub_users') || '[]');

    setUsers(registeredUsers);
    if (savedPosts) setPosts(JSON.parse(savedPosts));
    if (savedGroups) setGroups(JSON.parse(savedGroups));
    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedFriends) setFriends(JSON.parse(savedFriends));
  }, [user.username]);

  // Save Data
  useEffect(() => {
    localStorage.setItem('tig_community_posts', JSON.stringify(posts));
    localStorage.setItem('tig_community_groups', JSON.stringify(groups));
    localStorage.setItem('tig_community_messages', JSON.stringify(messages));
    localStorage.setItem(`tig_friends_${user.username}`, JSON.stringify(friends));
  }, [posts, groups, messages, friends, user.username]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'audio') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setMediaFile({ url: reader.result as string, type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPostContent && !mediaFile) return;

    const newPost: CommunityPost = {
      id: Date.now().toString(),
      author: user.name,
      authorUsername: user.username,
      content: newPostContent,
      mediaUrl: mediaFile?.url,
      mediaType: mediaFile?.type,
      likes: 0,
      comments: [],
      timestamp: new Date().toISOString(),
      groupId: selectedGroup || (viewingGroup ? viewingGroup.id : undefined)
    };

    setPosts([newPost, ...posts]);
    setNewPostContent('');
    setMediaFile(null);
    setSelectedGroup(null);
  };

  const handleAddFriend = (targetUsername: string) => {
    if (!friends.includes(targetUsername)) {
      setFriends([...friends, targetUsername]);
    }
  };

  const handleJoinGroup = (groupId: string) => {
    const updated = groups.map(g => g.id === groupId ? { ...g, isMember: true, memberCount: g.memberCount + 1 } : g);
    setGroups(updated);
  };

  const handleSendGroupMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupChatMsg.trim() || !viewingGroup) return;

    const newMsg: DirectMessage = {
      id: Date.now().toString(),
      sender: user.username,
      groupId: viewingGroup.id,
      content: groupChatMsg,
      timestamp: new Date().toISOString()
    };

    setMessages([...messages, newMsg]);
    setGroupChatMsg('');
  };

  // Filter Logic
  const filteredPosts = posts.filter(p => 
    (p.content.toLowerCase().includes(feedSearch.toLowerCase()) || p.author.toLowerCase().includes(feedSearch.toLowerCase())) &&
    (!viewingGroup || p.groupId === viewingGroup.id)
  );

  const filteredGroups = groups.filter(g => 
    g.name.toLowerCase().includes(groupSearch.toLowerCase()) || g.description.toLowerCase().includes(groupSearch.toLowerCase())
  );

  const filteredPeople = users.filter(u => 
    u.username !== user.username && 
    (u.name.toLowerCase().includes(peopleSearch.toLowerCase()) || u.username.toLowerCase().includes(peopleSearch.toLowerCase()))
  );

  return (
    <div className="flex flex-col lg:flex-row gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Sidebar Navigation */}
      <aside className="w-full lg:w-64 space-y-4 shrink-0">
        <div className={`p-4 rounded-3xl border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-sm'}`}>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] px-4 mb-4">Discovery</p>
          <div className="space-y-1">
            {[
              { id: 'feed', label: 'News Feed', icon: 'fa-house-signal' },
              { id: 'groups', label: 'Groups', icon: 'fa-cubes' },
              { id: 'people', label: 'Explore People', icon: 'fa-user-plus' },
              { id: 'messages', label: 'Messages', icon: 'fa-paper-plane' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => {
                  setActiveTab(tab.id as any);
                  setViewingGroup(null);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  activeTab === tab.id && !viewingGroup
                    ? (isDarkMode ? 'bg-indigo-600 text-white shadow-lg' : 'bg-black text-white shadow-lg') 
                    : (isDarkMode ? 'text-gray-400 hover:bg-white/5' : 'text-gray-500 hover:bg-gray-50')
                }`}
              >
                <i className={`fa-solid ${tab.icon} text-sm`}></i>
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Search Context Sidebar */}
        <div className={`p-6 rounded-3xl border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-sm'}`}>
           <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Filter Search</p>
           <div className="relative">
             <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-xs"></i>
             <input 
               type="text" 
               placeholder="Search context..."
               value={activeTab === 'feed' ? feedSearch : activeTab === 'groups' ? groupSearch : peopleSearch}
               onChange={(e) => {
                 if(activeTab === 'feed') setFeedSearch(e.target.value);
                 else if(activeTab === 'groups') setGroupSearch(e.target.value);
                 else setPeopleSearch(e.target.value);
               }}
               className={`w-full pl-9 pr-4 py-2.5 rounded-xl text-xs font-bold outline-none transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/10' : 'bg-gray-50 border-gray-200 text-black'}`}
             />
           </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 space-y-6">

        {/* VIEW: Group Detail with Hub & Chat */}
        {viewingGroup && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
            <div className={`p-8 rounded-[2.5rem] border overflow-hidden relative ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-xl'}`}>
               <button 
                 onClick={() => setViewingGroup(null)}
                 className="absolute top-6 right-6 text-gray-500 hover:text-rose-500 transition-colors"
               >
                 <i className="fa-solid fa-circle-xmark text-2xl"></i>
               </button>
               <div className="flex flex-col md:flex-row gap-6 items-start">
                 <div className={`${viewingGroup.color} w-20 h-20 rounded-[2rem] flex items-center justify-center text-white shadow-2xl`}>
                   <i className={`fa-solid ${viewingGroup.icon} text-4xl`}></i>
                 </div>
                 <div className="space-y-2">
                   <h2 className={`text-3xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{viewingGroup.name.toUpperCase()}</h2>
                   <p className="text-gray-500 font-medium max-w-xl">{viewingGroup.description}</p>
                   <div className="flex gap-4 items-center pt-2">
                     <span className="text-[10px] font-black text-indigo-500 bg-indigo-500/10 px-3 py-1.5 rounded-lg uppercase tracking-widest">{viewingGroup.memberCount} Participants</span>
                     {viewingGroup.isMember ? (
                       <span className="text-[10px] font-black text-emerald-500 bg-emerald-500/10 px-3 py-1.5 rounded-lg uppercase tracking-widest">Active Member</span>
                     ) : (
                       <button onClick={() => handleJoinGroup(viewingGroup.id)} className="px-6 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest">Join Lab</button>
                     )}
                   </div>
                 </div>
               </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
              {/* Group Feed */}
              <div className="space-y-6">
                <h3 className={`text-xs font-black uppercase tracking-[0.3em] ${isDarkMode ? 'text-white/40' : 'text-gray-400'}`}>Lab Logs</h3>
                {viewingGroup.isMember && (
                  <div className={`p-6 rounded-[2rem] border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100'}`}>
                    <form onSubmit={handleCreatePost} className="flex gap-4">
                      <input 
                        value={newPostContent}
                        onChange={(e) => setNewPostContent(e.target.value)}
                        placeholder="Log update to group..."
                        className={`flex-1 bg-transparent border-none outline-none text-sm font-bold ${isDarkMode ? 'text-white' : 'text-black'}`}
                      />
                      <button type="submit" className="text-indigo-500 hover:scale-110 transition-transform"><i className="fa-solid fa-paper-plane text-xl"></i></button>
                    </form>
                  </div>
                )}
                {filteredPosts.length === 0 ? (
                  <p className="text-center py-10 text-gray-500 font-bold uppercase text-[10px]">No logs in this sector</p>
                ) : (
                  filteredPosts.map(post => (
                    <div key={post.id} className={`p-6 rounded-[2rem] border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-lg'}`}>
                      <div className="flex items-center gap-3 mb-4">
                        <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${post.authorUsername}`} className="w-8 h-8 rounded-lg bg-gray-100" alt="" />
                        <div>
                          <p className="text-[10px] font-black uppercase tracking-wider">{post.author}</p>
                          <p className="text-[8px] text-gray-500 font-bold uppercase">{new Date(post.timestamp).toLocaleDateString()}</p>
                        </div>
                      </div>
                      <p className={`text-sm font-medium leading-relaxed ${isDarkMode ? 'text-gray-300' : 'text-gray-700'}`}>{post.content}</p>
                    </div>
                  ))
                )}
              </div>

              {/* Group Chat */}
              <div className="space-y-6">
                <h3 className={`text-xs font-black uppercase tracking-[0.3em] ${isDarkMode ? 'text-white/40' : 'text-gray-400'}`}>Secure Channel</h3>
                <div className={`h-[500px] flex flex-col rounded-[2.5rem] border overflow-hidden ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-2xl'}`}>
                  <div className="flex-1 p-6 overflow-y-auto space-y-4">
                    {messages.filter(m => m.groupId === viewingGroup.id).map(msg => (
                      <div key={msg.id} className={`flex ${msg.sender === user.username ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] p-3 px-4 rounded-2xl ${
                          msg.sender === user.username 
                            ? 'bg-indigo-600 text-white rounded-tr-none' 
                            : (isDarkMode ? 'bg-white/5 text-white rounded-tl-none border border-white/5' : 'bg-gray-100 text-gray-900 rounded-tl-none')
                        }`}>
                          <p className="text-[8px] font-black uppercase tracking-widest opacity-50 mb-1">{msg.sender}</p>
                          <p className="text-xs font-medium">{msg.content}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                  {viewingGroup.isMember ? (
                    <form onSubmit={handleSendGroupMessage} className={`p-4 border-t flex gap-3 ${isDarkMode ? 'border-white/5 bg-white/5' : 'border-gray-100 bg-gray-50'}`}>
                      <input 
                        type="text" 
                        value={groupChatMsg}
                        onChange={(e) => setGroupChatMsg(e.target.value)}
                        placeholder="Broadcast message..."
                        className={`flex-1 px-4 py-2.5 rounded-xl text-xs font-bold outline-none border-none ${isDarkMode ? 'bg-black text-white' : 'bg-white text-black shadow-inner'}`}
                      />
                      <button type="submit" className="w-10 h-10 rounded-xl bg-indigo-600 text-white flex items-center justify-center hover:scale-105 transition-all">
                        <i className="fa-solid fa-paper-plane text-xs"></i>
                      </button>
                    </form>
                  ) : (
                    <div className="p-6 text-center bg-rose-500/5 text-rose-500 font-black text-[10px] uppercase tracking-widest border-t border-rose-500/20">
                      Restricted Access • Join to broadcast
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* VIEW: Main Feed */}
        {activeTab === 'feed' && !viewingGroup && (
          <>
            <div className={`p-6 rounded-[2.5rem] border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-200 shadow-xl'}`}>
              <form onSubmit={handleCreatePost} className="space-y-4">
                <div className="flex gap-4">
                  <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-12 h-12 rounded-2xl overflow-hidden border-2 border-indigo-500 shrink-0" alt="" />
                  <textarea
                    value={newPostContent}
                    onChange={(e) => setNewPostContent(e.target.value)}
                    placeholder={`Publish to global feed, ${user.name}...`}
                    className={`flex-1 bg-transparent border-none focus:ring-0 text-lg font-medium resize-none py-2 ${isDarkMode ? 'placeholder:text-white/10 text-white' : 'placeholder:text-gray-300 text-gray-900'}`}
                    rows={2}
                  />
                </div>
                {mediaFile && (
                  <div className="relative rounded-2xl overflow-hidden border border-white/10">
                    <img src={mediaFile.url} alt="" className="w-full max-h-80 object-cover" />
                    <button type="button" onClick={() => setMediaFile(null)} className="absolute top-4 right-4 w-8 h-8 rounded-full bg-black/50 text-white"><i className="fa-solid fa-xmark"></i></button>
                  </div>
                )}
                <div className={`pt-4 border-t flex items-center justify-between ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
                  <div className="flex gap-2">
                    <label className={`w-10 h-10 rounded-xl flex items-center justify-center cursor-pointer ${isDarkMode ? 'bg-white/5 text-gray-400' : 'bg-gray-100 text-gray-500'}`}>
                      <i className="fa-solid fa-image text-sm"></i>
                      <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileUpload(e, 'image')} />
                    </label>
                  </div>
                  <button type="submit" className="px-8 py-2.5 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest">Broadcast Post</button>
                </div>
              </form>
            </div>
            <div className="space-y-6">
              {filteredPosts.filter(p => !p.groupId).map(post => (
                <div key={post.id} className={`p-8 rounded-[2.5rem] border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5 shadow-2xl' : 'bg-white border-gray-100 shadow-xl'}`}>
                  <div className="flex items-center gap-4 mb-6">
                    <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${post.authorUsername}`} className="w-12 h-12 rounded-2xl bg-gray-100" alt="" />
                    <div className="flex-1">
                      <h4 className={`text-sm font-black uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{post.author}</h4>
                      <p className="text-[10px] font-bold text-gray-500">@{post.authorUsername} • {new Date(post.timestamp).toLocaleTimeString()}</p>
                    </div>
                  </div>
                  <p className={`text-lg leading-relaxed mb-6 font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-700'}`}>{post.content}</p>
                  {post.mediaUrl && <img src={post.mediaUrl} className="w-full rounded-3xl mb-6" alt="" />}
                  <div className={`pt-6 border-t flex items-center gap-6 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
                    <button className="flex items-center gap-2 text-rose-500 font-black text-[10px] uppercase tracking-widest hover:scale-105 transition-transform"><i className="fa-solid fa-heart"></i> {post.likes} Likes</button>
                    <button className="flex items-center gap-2 text-gray-400 font-black text-[10px] uppercase tracking-widest"><i className="fa-solid fa-comment"></i> {post.comments.length} Comments</button>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {/* VIEW: Groups Search & List */}
        {activeTab === 'groups' && !viewingGroup && (
          <div className="space-y-8">
            <div className="flex items-center justify-between">
              <h2 className={`text-3xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>SECTOR DIRECTORY</h2>
              <button onClick={() => setShowGroupModal(true)} className="px-6 py-3 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all">Establish Lab</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {filteredGroups.map(group => (
                <div key={group.id} className={`p-8 rounded-[2.5rem] border group transition-all hover:-translate-y-1 ${isDarkMode ? 'bg-[#0a0a0a] border-white/5 shadow-2xl' : 'bg-white border-gray-100 shadow-xl'}`}>
                  <div className={`${group.color} w-14 h-14 rounded-2xl flex items-center justify-center text-white mb-6 shadow-lg group-hover:scale-110 transition-transform`}>
                    <i className={`fa-solid ${group.icon} text-2xl`}></i>
                  </div>
                  <h3 className={`text-xl font-black tracking-tight mb-2 ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{group.name}</h3>
                  <p className="text-sm text-gray-500 font-medium mb-6 line-clamp-2">{group.description}</p>
                  <div className="flex items-center justify-between mt-auto">
                    <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 bg-indigo-500/10 px-3 py-1.5 rounded-lg">{group.memberCount} Staff</span>
                    <button onClick={() => setViewingGroup(group)} className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isDarkMode ? 'bg-white/5 text-white hover:bg-indigo-600' : 'bg-gray-100 text-gray-900 hover:bg-black hover:text-white'}`}>Open Hub</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* VIEW: Explore People & Add Friends */}
        {activeTab === 'people' && (
          <div className="space-y-8">
            <h2 className={`text-3xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>USER INDEX</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-6">
              {filteredPeople.map(u => (
                <div key={u.username} className={`p-6 rounded-3xl border flex items-center gap-4 transition-all hover:border-indigo-500 ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-sm'}`}>
                  <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${u.username}`} className="w-12 h-12 rounded-xl bg-gray-100" alt="" />
                  <div className="flex-1 min-w-0">
                    <p className={`text-xs font-black uppercase tracking-widest truncate ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{u.name}</p>
                    <p className="text-[10px] font-bold text-gray-500 truncate">@{u.username}</p>
                  </div>
                  {friends.includes(u.username) ? (
                    <div className="text-emerald-500 bg-emerald-500/10 w-8 h-8 rounded-lg flex items-center justify-center" title="Connected">
                       <i className="fa-solid fa-check-double text-xs"></i>
                    </div>
                  ) : (
                    <button onClick={() => handleAddFriend(u.username)} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isDarkMode ? 'bg-white/5 text-indigo-400 hover:bg-indigo-600 hover:text-white' : 'bg-indigo-50 text-indigo-600 hover:bg-black hover:text-white'}`}>
                      <i className="fa-solid fa-user-plus text-xs"></i>
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* VIEW: Direct Messages */}
        {activeTab === 'messages' && (
           <div className={`flex flex-col h-[70vh] rounded-[2.5rem] border overflow-hidden ${isDarkMode ? 'bg-[#0a0a0a] border-white/5 shadow-2xl' : 'bg-white border-gray-100 shadow-xl'}`}>
             <div className="flex-1 p-8 overflow-y-auto space-y-4">
               {messages.filter(m => !m.groupId).length === 0 ? (
                 <div className="h-full flex flex-col items-center justify-center text-center space-y-4 opacity-30">
                    <i className="fa-solid fa-tower-broadcast text-4xl mb-4"></i>
                    <p className="text-xs font-black uppercase tracking-[0.2em]">Private Link Terminal</p>
                 </div>
               ) : (
                 messages.filter(m => !m.groupId).map(msg => (
                    <div key={msg.id} className={`flex ${msg.sender === user.username ? 'justify-end' : 'justify-start'}`}>
                       <div className={`max-w-[70%] p-4 rounded-2xl ${msg.sender === user.username ? 'bg-indigo-600 text-white' : 'bg-gray-100'}`}>
                         <p className="text-xs font-medium">{msg.content}</p>
                       </div>
                    </div>
                 ))
               )}
             </div>
             <div className="p-6 border-t border-white/5"><p className="text-[10px] font-bold text-gray-500 italic text-center uppercase tracking-widest">Select a connected user from Index to initiate direct uplink</p></div>
           </div>
        )}
      </div>

      {/* New Group Modal - Reused from previous state but ensuring functionality */}
      {showGroupModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className={`w-full max-w-lg rounded-[2.5rem] border shadow-2xl overflow-hidden animate-in zoom-in-95 ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-200'}`}>
            <div className="p-8 border-b border-white/5 flex items-center justify-between">
              <h2 className={`text-xl font-black uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Establish Sector</h2>
              <button onClick={() => setShowGroupModal(false)} className="text-gray-500 hover:text-rose-500 transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Group Name</label>
                <input id="groupName" className={`w-full px-5 py-4 rounded-2xl outline-none border transition-all ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200 text-gray-900'}`} placeholder="Sector Designation" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Mission Objective</label>
                <textarea id="groupDesc" className={`w-full px-5 py-4 rounded-2xl outline-none border transition-all resize-none ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200 text-gray-900'}`} placeholder="Sector briefing..." rows={3} />
              </div>
              <button 
                onClick={() => {
                  const n = (document.getElementById('groupName') as HTMLInputElement).value;
                  const d = (document.getElementById('groupDesc') as HTMLTextAreaElement).value;
                  if(n && d) {
                    const newGroup: CommunityGroup = {
                      id: Date.now().toString(),
                      name: n,
                      description: d,
                      creator: user.username,
                      memberCount: 1,
                      icon: 'fa-cube',
                      color: 'bg-indigo-600',
                      isMember: true
                    };
                    setGroups([newGroup, ...groups]);
                    setShowGroupModal(false);
                  }
                }}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl"
              >
                Sync Community Sector
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Community;

export interface Slide {
  id: string;
  title: string;
  content: string[];
  speakerNotes: string;
  imageUrl?: string;
}

export interface Presentation {
  title: string;
  description: string;
  slides: Slide[];
}

export interface AppItem {
  id: string;
  name: string;
  description: string;
  icon: string;
  category: string;
  url: string;
  color: string;
}

export interface User {
  username: string;
  password?: string;
  name: string;
}

// Community Types
export interface SurveyOption {
  id: string;
  text: string;
  votes: number;
  voters: string[]; // List of usernames who voted for this option
}

export interface Survey {
  question: string;
  options: SurveyOption[];
  totalVotes: number;
}

export interface CommunityComment {
  id: string;
  author: string;
  content: string;
  mediaUrl?: string;
  mediaType?: 'image' | 'audio';
  timestamp: string;
}

export interface CommunityPost {
  id: string;
  author: string;
  authorUsername: string;
  content: string;
  mediaUrl?: string;
  mediaType?: 'image' | 'audio';
  survey?: Survey;
  likes: number;
  comments: CommunityComment[];
  timestamp: string;
  groupId?: string;
}

export interface CommunityGroup {
  id: string;
  name: string;
  description: string;
  creator: string;
  memberCount: number;
  icon: string;
  color: string;
  isMember?: boolean;
}

export interface DirectMessage {
  id: string;
  sender: string;
  receiver?: string; // Dùng cho DM
  groupId?: string;  // Dùng cho Group Chat
  content: string;
  mediaUrl?: string;
  mediaType?: 'image' | 'audio';
  timestamp: string;
}

export interface FriendRelation {
  username: string;
  status: 'friend' | 'pending';
}

import React, { useState, useEffect } from 'react';
import { User, CommunityPost, CommunityGroup, DirectMessage, CommunityComment, Survey, SurveyOption } from '../types';

const Community: React.FC<{ isDarkMode: boolean; user: User }> = ({ isDarkMode, user }) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'groups' | 'people' | 'messages'>('feed');
  const [posts, setPosts] = useState<CommunityPost[]>([]);
  const [groups, setGroups] = useState<CommunityGroup[]>([]);
  const [messages, setMessages] = useState<DirectMessage[]>([]);
  const [friends, setFriends] = useState<string[]>([]);
  const [users, setUsers] = useState<User[]>([]);

  // States for Search
  const [feedSearch, setFeedSearch] = useState('');
  const [groupSearch, setGroupSearch] = useState('');
  const [peopleSearch, setPeopleSearch] = useState('');

  // States for Group Detail & Chat
  const [viewingGroup, setViewingGroup] = useState<CommunityGroup | null>(null);
  const [groupChatMsg, setGroupChatMsg] = useState('');

  // Create Post States
  const [newPostContent, setNewPostContent] = useState('');
  const [mediaFile, setMediaFile] = useState<{url: string, type: 'image' | 'audio'} | null>(null);
  const [isSurveyMode, setIsSurveyMode] = useState(false);
  const [surveyQuestion, setSurveyQuestion] = useState('');
  const [surveyOptions, setSurveyOptions] = useState<string[]>(['', '']);

  const [showGroupModal, setShowGroupModal] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState<string | null>(null);

  // Load Data
  useEffect(() => {
    const savedPosts = localStorage.getItem('tig_community_posts');
    const savedGroups = localStorage.getItem('tig_community_groups');
    const savedMessages = localStorage.getItem('tig_community_messages');
    const savedFriends = localStorage.getItem(`tig_friends_${user.username}`);
    const registeredUsers = JSON.parse(localStorage.getItem('tig_hub_users') || '[]');

    setUsers(registeredUsers);
    if (savedPosts) setPosts(JSON.parse(savedPosts));
    if (savedGroups) setGroups(JSON.parse(savedGroups));
    if (savedMessages) setMessages(JSON.parse(savedMessages));
    if (savedFriends) setFriends(JSON.parse(savedFriends));
  }, [user.username]);

  // Save Data
  useEffect(() => {
    localStorage.setItem('tig_community_posts', JSON.stringify(posts));
    localStorage.setItem('tig_community_groups', JSON.stringify(groups));
    localStorage.setItem('tig_community_messages', JSON.stringify(messages));
    localStorage.setItem(`tig_friends_${user.username}`, JSON.stringify(friends));
  }, [posts, groups, messages, friends, user.username]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'image' | 'audio') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setMediaFile({ url: reader.result as string, type });
      };
      reader.readAsDataURL(file);
    }
  };

  const addSurveyOption = () => {
    if (surveyOptions.length < 5) {
      setSurveyOptions([...surveyOptions, '']);
    }
  };

  const removeSurveyOption = (index: number) => {
    if (surveyOptions.length > 2) {
      const updated = surveyOptions.filter((_, i) => i !== index);
      setSurveyOptions(updated);
    }
  };

  const updateSurveyOption = (index: number, text: string) => {
    const updated = [...surveyOptions];
    updated[index] = text;
    setSurveyOptions(updated);
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPostContent && !mediaFile && !isSurveyMode) return;
    if (isSurveyMode && (!surveyQuestion || surveyOptions.some(opt => !opt.trim()))) return;

    let postSurvey: Survey | undefined = undefined;
    if (isSurveyMode) {
      postSurvey = {
        question: surveyQuestion,
        totalVotes: 0,
        options: surveyOptions.map((opt, i) => ({
          id: `opt-${Date.now()}-${i}`,
          text: opt,
          votes: 0,
          voters: []
        }))
      };
    }

    const newPost: CommunityPost = {
      id: Date.now().toString(),
      author: user.name,
      authorUsername: user.username,
      content: newPostContent,
      mediaUrl: mediaFile?.url,
      mediaType: mediaFile?.type,
      survey: postSurvey,
      likes: 0,
      comments: [],
      timestamp: new Date().toISOString(),
      groupId: selectedGroup || (viewingGroup ? viewingGroup.id : undefined)
    };

    setPosts([newPost, ...posts]);

    // Reset form
    setNewPostContent('');
    setMediaFile(null);
    setSelectedGroup(null);
    setIsSurveyMode(false);
    setSurveyQuestion('');
    setSurveyOptions(['', '']);
  };

  const handleVote = (postId: string, optionId: string) => {
    const updatedPosts = posts.map(post => {
      if (post.id === postId && post.survey) {
        // Check if user already voted in this survey
        const hasVoted = post.survey.options.some(opt => opt.voters.includes(user.username));
        if (hasVoted) return post;

        const updatedOptions = post.survey.options.map(opt => {
          if (opt.id === optionId) {
            return {
              ...opt,
              votes: opt.votes + 1,
              voters: [...opt.voters, user.username]
            };
          }
          return opt;
        });

        return {
          ...post,
          survey: {
            ...post.survey,
            options: updatedOptions,
            totalVotes: post.survey.totalVotes + 1
          }
        };
      }
      return post;
    });
    setPosts(updatedPosts);
  };

  const handleAddFriend = (targetUsername: string) => {
    if (!friends.includes(targetUsername)) {
      setFriends([...friends, targetUsername]);
    }
  };

  const handleJoinGroup = (groupId: string) => {
    const updated = groups.map(g => g.id === groupId ? { ...g, isMember: true, memberCount: g.memberCount + 1 } : g);
    setGroups(updated);
  };

  const handleSendGroupMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupChatMsg.trim() || !viewingGroup) return;

    const newMsg: DirectMessage = {
      id: Date.now().toString(),
      sender: user.username,
      groupId: viewingGroup.id,
      content: groupChatMsg,
      timestamp: new Date().toISOString()
    };

    setMessages([...messages, newMsg]);
    setGroupChatMsg('');
  };

  // Filter Logic
  const filteredPosts = posts.filter(p => 
    (p.content.toLowerCase().includes(feedSearch.toLowerCase()) || 
     p.author.toLowerCase().includes(feedSearch.toLowerCase()) ||
     (p.survey?.question.toLowerCase().includes(feedSearch.toLowerCase()))) &&
    (!viewingGroup || p.groupId === viewingGroup.id)
  );

  const filteredGroups = groups.filter(g => 
    g.name.toLowerCase().includes(groupSearch.toLowerCase()) || g.description.toLowerCase().includes(groupSearch.toLowerCase())
  );

  const filteredPeople = users.filter(u => 
    u.username !== user.username && 
    (u.name.toLowerCase().includes(peopleSearch.toLowerCase()) || u.username.toLowerCase().includes(peopleSearch.toLowerCase()))
  );

  const renderSurvey = (post: CommunityPost) => {
    if (!post.survey) return null;
    const hasVoted = post.survey.options.some(opt => opt.voters.includes(user.username));

    return (
      <div className={`mt-6 p-6 rounded-3xl border ${isDarkMode ? 'bg-white/5 border-white/5' : 'bg-gray-50 border-gray-100'}`}>
        <h4 className={`text-lg font-black mb-4 ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{post.survey.question}</h4>
        <div className="space-y-3">
          {post.survey.options.map((option) => {
            const percentage = post.survey!.totalVotes === 0 ? 0 : Math.round((option.votes / post.survey!.totalVotes) * 100);
            const isUserChoice = option.voters.includes(user.username);

            return (
              <div key={option.id} className="relative group">
                {hasVoted ? (
                  <div className="flex flex-col gap-1">
                    <div className="flex justify-between text-[10px] font-black uppercase tracking-widest mb-1">
                      <span className={isUserChoice ? 'text-indigo-500' : (isDarkMode ? 'text-gray-400' : 'text-gray-500')}>
                        {option.text} {isUserChoice && '(Voted)'}
                      </span>
                      <span className={isDarkMode ? 'text-white' : 'text-black'}>{percentage}%</span>
                    </div>
                    <div className={`h-3 w-full rounded-full overflow-hidden ${isDarkMode ? 'bg-white/5' : 'bg-gray-200'}`}>
                      <div 
                        className={`h-full transition-all duration-1000 ${isUserChoice ? 'bg-indigo-600' : 'bg-indigo-400 opacity-40'}`}
                        style={{ width: `${percentage}%` }}
                      ></div>
                    </div>
                  </div>
                ) : (
                  <button
                    onClick={() => handleVote(post.id, option.id)}
                    className={`w-full text-left px-5 py-3 rounded-2xl border text-sm font-bold transition-all hover:border-indigo-500 hover:bg-indigo-500/5 ${
                      isDarkMode ? 'bg-white/5 border-white/10 text-white' : 'bg-white border-gray-200 text-gray-700'
                    }`}
                  >
                    {option.text}
                  </button>
                )}
              </div>
            );
          })}
        </div>
        <div className="mt-4 text-[9px] font-black uppercase tracking-[0.2em] text-gray-400">
          {post.survey.totalVotes} Total Votes
        </div>
      </div>
    );
  };

  const renderCreatePostArea = () => (
    <div className={`p-6 rounded-[2.5rem] border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-200 shadow-xl'}`}>
      <form onSubmit={handleCreatePost} className="space-y-4">
        <div className="flex gap-4">
          <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} className="w-12 h-12 rounded-2xl overflow-hidden border-2 border-indigo-500 shrink-0" alt="" />
          <div className="flex-1 space-y-4">
            <textarea
              value={newPostContent}
              onChange={(e) => setNewPostContent(e.target.value)}
              placeholder={isSurveyMode ? "Add a caption for your poll..." : `Publish to ${viewingGroup ? viewingGroup.name : 'global feed'}, ${user.name}...`}
              className={`w-full bg-transparent border-none focus:ring-0 text-lg font-medium resize-none py-2 ${isDarkMode ? 'placeholder:text-white/10 text-white' : 'placeholder:text-gray-300 text-gray-900'}`}
              rows={isSurveyMode ? 1 : 2}
            />

            {isSurveyMode && (
              <div className={`p-6 rounded-3xl border animate-in slide-in-from-top-4 duration-300 ${isDarkMode ? 'bg-white/5 border-white/5' : 'bg-gray-50 border-gray-200'}`}>
                <div className="mb-4">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Poll Question</label>
                   <input 
                     value={surveyQuestion}
                     onChange={(e) => setSurveyQuestion(e.target.value)}
                     className={`w-full px-4 py-3 rounded-xl outline-none border transition-all ${isDarkMode ? 'bg-black border-white/10 text-white focus:border-indigo-500' : 'bg-white border-gray-200 text-black'}`}
                     placeholder="What do you want to ask?"
                   />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 block">Options</label>
                  {surveyOptions.map((opt, i) => (
                    <div key={i} className="flex gap-2">
                      <input 
                        value={opt}
                        onChange={(e) => updateSurveyOption(i, e.target.value)}
                        className={`flex-1 px-4 py-2 rounded-xl outline-none border transition-all text-xs font-bold ${isDarkMode ? 'bg-black border-white/10 text-white focus:border-indigo-500' : 'bg-white border-gray-200 text-black'}`}
                        placeholder={`Option ${i + 1}`}
                      />
                      {surveyOptions.length > 2 && (
                        <button type="button" onClick={() => removeSurveyOption(i)} className="text-rose-500 hover:scale-110 transition-transform"><i className="fa-solid fa-circle-minus"></i></button>
                      )}
                    </div>
                  ))}
                  {surveyOptions.length < 5 && (
                    <button 
                      type="button" 
                      onClick={addSurveyOption}
                      className="text-[10px] font-black uppercase tracking-widest text-indigo-500 hover:text-indigo-400 transition-colors py-2"
                    >
                      + Add Option
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>

        {mediaFile && !isSurveyMode && (
          <div className="relative rounded-2xl overflow-hidden border border-white/10">
            <img src={mediaFile.url} alt="" className="w-full max-h-80 object-cover" />
            <button type="button" onClick={() => setMediaFile(null)} className="absolute top-4 right-4 w-8 h-8 rounded-full bg-black/50 text-white"><i className="fa-solid fa-xmark"></i></button>
          </div>
        )}

        <div className={`pt-4 border-t flex items-center justify-between ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
          <div className="flex gap-2">
            <button 
              type="button"
              onClick={() => setIsSurveyMode(!isSurveyMode)}
              className={`w-10 h-10 rounded-xl flex items-center justify-center cursor-pointer transition-all ${isSurveyMode ? 'bg-indigo-600 text-white' : (isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-100 text-gray-500 hover:bg-black hover:text-white')}`}
              title="Create Poll"
            >
              <i className="fa-solid fa-square-poll-vertical text-sm"></i>
            </button>
            {!isSurveyMode && (
              <label className={`w-10 h-10 rounded-xl flex items-center justify-center cursor-pointer transition-all ${isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-100 text-gray-500 hover:bg-black hover:text-white'}`}>
                <i className="fa-solid fa-image text-sm"></i>
                <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileUpload(e, 'image')} />
              </label>
            )}
            <label className={`w-10 h-10 rounded-xl flex items-center justify-center cursor-pointer transition-all ${isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-100 text-gray-500 hover:bg-black hover:text-white'}`}>
              <i className="fa-solid fa-microphone text-sm"></i>
              <input type="file" accept="audio/*" className="hidden" onChange={(e) => handleFileUpload(e, 'audio')} />
            </label>
          </div>
          <button type="submit" className="px-8 py-2.5 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-500/20 active:scale-95">
            {isSurveyMode ? 'Initialize Poll' : 'Broadcast Post'}
          </button>
        </div>
      </form>
    </div>
  );

  return (
    <div className="flex flex-col lg:flex-row gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Sidebar Navigation */}
      <aside className="w-full lg:w-64 space-y-4 shrink-0">
        <div className={`p-4 rounded-3xl border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-sm'}`}>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] px-4 mb-4">Discovery</p>
          <div className="space-y-1">
            {[
              { id: 'feed', label: 'News Feed', icon: 'fa-house-signal' },
              { id: 'groups', label: 'Groups', icon: 'fa-cubes' },
              { id: 'people', label: 'Explore People', icon: 'fa-user-plus' },
              { id: 'messages', label: 'Messages', icon: 'fa-paper-plane' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => {
                  setActiveTab(tab.id as any);
                  setViewingGroup(null);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  activeTab === tab.id && !viewingGroup
                    ? (isDarkMode ? 'bg-indigo-600 text-white shadow-lg' : 'bg-black text-white shadow-lg') 
                    : (isDarkMode ? 'text-gray-400 hover:bg-white/5' : 'text-gray-500 hover:bg-gray-50')
                }`}
              >
                <i className={`fa-solid ${tab.icon} text-sm`}></i>
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Search Context Sidebar */}
        <div className={`p-6 rounded-3xl border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-sm'}`}>
           <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Filter Search</p>
           <div className="relative">
             <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-xs"></i>
             <input 
               type="text" 
               placeholder="Search context..."
               value={activeTab === 'feed' ? feedSearch : activeTab === 'groups' ? groupSearch : peopleSearch}
               onChange={(e) => {
                 if(activeTab === 'feed') setFeedSearch(e.target.value);
                 else if(activeTab === 'groups') setGroupSearch(e.target.value);
                 else setPeopleSearch(e.target.value);
               }}
               className={`w-full pl-9 pr-4 py-2.5 rounded-xl text-xs font-bold outline-none transition-all ${isDarkMode ? 'bg-white/5 text-white border-white/10' : 'bg-gray-50 border-gray-200 text-black'}`}
             />
           </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 space-y-6">

        {/* VIEW: Group Detail with Hub & Chat */}
        {viewingGroup && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
            <div className={`p-8 rounded-[2.5rem] border overflow-hidden relative ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100 shadow-xl'}`}>
               <button 
                 onClick={() => setViewingGroup(null)}
                 className="absolute top-6 right-6 text-gray-500 hover:text-rose-500 transition-colors"
               >
                 <i className="fa-solid fa-circle-xmark text-2xl"></i>
