                    {messages.filter(m => m.groupId === viewingGroup.id).map(msg => (
                      <div key={msg.id} className={`flex ${msg.sender === user.username ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] p-3 px-4 rounded-2xl ${
                          msg.sender === user.username 
                            ? 'bg-indigo-600 text-white rounded-tr-none' 
                            : (isDarkMode ? 'bg-white/5 text-white rounded-tl-none border border-white/5' : 'bg-gray-100 text-gray-900 rounded-tl-none')
                        }`}>
                          <p className="text-[8px] font-black uppercase tracking-widest opacity-50 mb-1">{msg.sender}</p>
