                    <button onClick={() => handleAddFriend(u.username)} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isDarkMode ? 'bg-white/5 text-indigo-400 hover:bg-indigo-600 hover:text-white' : 'bg-indigo-50 text-indigo-600 hover:bg-black hover:text-white'}`}>
                      <i className="fa-solid fa-user-plus text-xs"></i>
                    </button>
                  )}
