import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "../types";

/**
 * Helper to initialize GoogleGenAI with the required API key from environment.
 */
const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a structured presentation including slides and speaker notes based on a topic.
 * Uses gemini-3-flash-preview for high-quality structured text generation.
 */
export const generatePresentation = async (topic: string, style: string): Promise<Presentation> => {
  const ai = getAi();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Create a professional presentation about "${topic}" in a "${style}" tone. 
    The output should be a JSON object containing a title, a short description, 
    and exactly 5 slides. Each slide needs a title, an array of 3-4 content points, 
    and speaker notes.`,
    config: {
      systemInstruction: "You are an expert presentation consultant. Always return valid JSON matching the requested schema.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          slides: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                speakerNotes: { type: Type.STRING }
              },
              required: ["title", "content", "speakerNotes"]
            }
          }
        },
        required: ["title", "description", "slides"]
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("Failed to receive a valid response from Gemini.");
  }

  const data = JSON.parse(text);

  return {
    id: Date.now().toString(),
    title: data.title,
    description: data.description,
    createdAt: new Date().toISOString(),
    slides: data.slides.map((s: any, i: number) => ({
      ...s,
      id: `slide-${i}-${Date.now()}`
    }))
  };
};

/**
 * Generates an image for a specific presentation slide using gemini-2.5-flash-image.
 */
export const generateImageForSlide = async (title: string, content: string): Promise<string> => {
  const ai = getAi();
  const prompt = `A professional, modern, and high-quality presentation graphic for a slide titled: "${title}". 
  The content focuses on: "${content}". 
  Style: Minimalist corporate, cinematic lighting, 4k resolution.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  // Iterate through parts to find the image part
  for (const candidate of response.candidates || []) {
    for (const part of candidate.content.parts) {
      if (part.inlineData) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
  }

  throw new Error("Model failed to generate an image for the slide.");
};

