const AppCard: React.FC<{ 
  app: AppItem; 
  onDelete?: (id: string) => void; 
  onUpdateUrl?: (id: string, newUrl: string) => void;
  isCustom?: boolean; 
  isDarkMode: boolean 
}> = ({ app, onDelete, onUpdateUrl, isCustom, isDarkMode }) => {
  const [isLaunching, setIsLaunching] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [tempUrl, setTempUrl] = useState(app.url);

  const handleLaunch = () => {
    if (isEditing) return;
    setIsLaunching(true);
    setTimeout(() => {
      window.open(app.url, '_blank', 'noopener,noreferrer');
      setIsLaunching(false);
    }, 800);
  };

  const saveUrl = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onUpdateUrl) onUpdateUrl(app.id, tempUrl);
    setIsEditing(false);
  };

  return (
    <div 
      onClick={handleLaunch}
      className={`group relative rounded-[2.5rem] p-8 border transition-all duration-500 hover:-translate-y-3 cursor-pointer overflow-hidden ${
      isDarkMode 
        ? 'bg-[#0a0a0a] border-white/5 shadow-[0_20px_50px_rgba(0,0,0,0.5)] hover:shadow-indigo-500/20' 
        : 'bg-white border-gray-100 shadow-xl hover:shadow-indigo-500/10'
    }`}>
      {/* Background Animated Glow */}
