      <div className="absolute top-6 right-6 flex gap-2 z-20 opacity-0 group-hover:opacity-100 transition-all">
        <button 
          onClick={(e) => {
            e.stopPropagation();
            setIsEditing(!isEditing);
          }}
          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${
            isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-50 text-gray-500 hover:bg-black hover:text-white'
          }`}
          title="Sửa Link"
        >
          <i className="fa-solid fa-link text-xs"></i>
        </button>
        {isCustom && onDelete && (
          <button 
            onClick={(e) => {
              e.stopPropagation();
              if (window.confirm('Gỡ bỏ ứng dụng này khỏi Hub?')) {
                onDelete(app.id);
              }
            }}
            className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center hover:bg-rose-500 hover:text-white ${
              isDarkMode ? 'bg-white/5 text-rose-500' : 'bg-rose-50 text-rose-500'
