};

const Dashboard: React.FC<{ isDarkMode: boolean }> = ({ isDarkMode }) => {
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);
  const [systemApps, setSystemApps] = useState<AppItem[]>(APPS);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedZip, setSelectedZip] = useState<File | null>(null);

  useEffect(() => {
    const storedApps = localStorage.getItem('tig_hub_custom_apps');
    if (storedApps) try { setCustomApps(JSON.parse(storedApps)); } catch (e) {}

    const storedSystem = localStorage.getItem('tig_hub_system_apps');
    if (storedSystem) try { setSystemApps(JSON.parse(storedSystem)); } catch (e) {}
  }, []);

  const handleUpdateUrl = (id: string, newUrl: string) => {
    if (systemApps.some(a => a.id === id)) {
      const updated = systemApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setSystemApps(updated);
      localStorage.setItem('tig_hub_system_apps', JSON.stringify(updated));
    } else {
      const updated = customApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
    }
  };

  const handleDeploy = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedZip) {
      alert("Vui lòng chọn file ZIP để tiếp tục.");
      return;
    }

    const form = e.target as any;
    const appName = form.appName.value;
    const appDesc = form.appDesc.value;

    setIsUploading(true);
    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 15;
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);

        const newApp: AppItem = {
          id: Date.now().toString(),
          name: appName,
          description: appDesc,
          url: '', // ZIP uploaded app initially has no URL
          icon: 'fa-box-archive',
          category: 'ZIP Deployment',
          color: 'bg-indigo-600',
          developer: 'TIG-Minh',
          zipFile: {
            name: selectedZip.name,
            size: selectedZip.size
          }
        };

        const updated = [newApp, ...customApps];
        setCustomApps(updated);
        localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));

        setIsUploading(false);
        setIsModalOpen(false);
        setSelectedZip(null);
        setUploadProgress(0);
      }
      setUploadProgress(progress);
    }, 200);
  };

  const displayApps = [...customApps.map(a => ({ ...a, isCustom: true })), ...systemApps];
  const filteredApps = displayApps.filter(app => {
    const name = app.name || '';
    const category = app.category || '';
    return name.toLowerCase().includes(search.toLowerCase()) ||
           category.toLowerCase().includes(search.toLowerCase());
  });

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <section className={`flex flex-col md:flex-row md:items-end justify-between gap-8 border-b pb-12 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className="space-y-4">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-black text-white'}`}>
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
            Interface: Online • Made by TIG-Minh
          </div>
          <h1 className={`text-6xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>MY COMMANDER</h1>
          <p className="text-gray-500 max-w-lg font-medium text-lg">
            Hệ sinh thái ứng dụng của <span className="text-indigo-500 font-bold">Minh</span>. Tải lên file ZIP để triển khai module mới.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-1 sm:w-80 group">
            <i className={`fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 transition-colors ${isDarkMode ? 'text-gray-600 group-focus-within:text-white' : 'text-gray-400 group-focus-within:text-black'}`}></i>
            <input
              type="text"
              placeholder="Sách ứng dụng..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className={`w-full pl-11 pr-4 py-5 rounded-[1.5rem] border-none transition-all outline-none font-bold text-sm ${
                isDarkMode ? 'bg-white/5 text-white focus:ring-2 focus:ring-indigo-500/50' : 'bg-gray-100 text-gray-900 focus:ring-2 focus:ring-black'
              }`}
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className={`px-8 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-2xl active:scale-95 ${
              isDarkMode ? 'bg-white text-black hover:bg-indigo-600 hover:text-white' : 'bg-black text-white hover:bg-indigo-600'
            }`}
          >
            <i className="fa-solid fa-cloud-arrow-up text-xs"></i>
            Deploy ZIP Module
          </button>
        </div>
      </section>

      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
        {filteredApps.map((app: any, idx) => (
          <AppCard 
            key={app.id || idx} 
            app={app} 
            isDarkMode={isDarkMode}
            isCustom={app.isCustom}
            onDelete={handleDeleteApp}
            onUpdateUrl={handleUpdateUrl}
          />
        ))}
      </section>

      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-xl animate-in fade-in duration-300">
           <div className={`w-full max-w-lg rounded-[3rem] border shadow-2xl overflow-hidden animate-in zoom-in-95 ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-200'}`}>
             <div className="p-10 border-b border-white/5 flex items-center justify-between">
                <div>
                  <h2 className={`text-2xl font-black uppercase tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Deploy Module</h2>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-[0.3em] mt-1">ZIP Deployment Protocol</p>
                </div>
                <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-full flex items-center justify-center text-gray-500 hover:bg-rose-500 hover:text-white transition-all">
                  <i className="fa-solid fa-xmark text-lg"></i>
                </button>
             </div>
             <div className="p-10 space-y-6">
                <form onSubmit={handleDeploy} className="space-y-5">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">App Name</label>
                    <input name="appName" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="E.g. Chat System" />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Upload Package (.zip only)</label>
                    <label className={`block w-full border-2 border-dashed rounded-2xl p-8 text-center cursor-pointer transition-all ${
                      selectedZip ? 'border-emerald-500 bg-emerald-500/5' : (isDarkMode ? 'border-white/10 hover:border-indigo-500' : 'border-gray-200 hover:border-black')
                    }`}>
                      <input 
                        type="file" 
                        accept=".zip" 
                        className="hidden" 
                        onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (file && file.name.endsWith('.zip')) {
                            setSelectedZip(file);
                          } else if (file) {
                            alert("Chỉ chấp nhận file định dạng .zip");
                          }
                        }}
                      />
                      <i className={`fa-solid ${selectedZip ? 'fa-file-zipper text-emerald-500' : 'fa-folder-open text-gray-400'} text-3xl mb-3`}></i>
                      <p className={`text-xs font-black uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>
                        {selectedZip ? selectedZip.name : 'Click to select ZIP file'}
                      </p>
                      {selectedZip && <p className="text-[9px] text-emerald-500 mt-2 font-bold uppercase tracking-tighter">Package Ready: {Math.round(selectedZip.size/1024/1024*10)/10} MB</p>}
                    </label>
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Description</label>
                    <textarea name="appDesc" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all resize-none font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="Brief app overview..." rows={2} />
                  </div>

                  {isUploading && (
                    <div className="space-y-2">
                       <div className="flex justify-between text-[10px] font-black uppercase text-indigo-400 tracking-widest">
                          <span>Extracting & Deploying...</span>
                          <span>{Math.round(uploadProgress)}%</span>
                       </div>
                       <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden">
                          <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }}></div>
                       </div>
                    </div>
                  )}

                  <button 
                    type="submit" 
                    disabled={isUploading || !selectedZip}
                    className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.3em] shadow-xl hover:-translate-y-1 transition-all disabled:opacity-50"
                  >
                    Deploy Module to Hub
                  </button>
                </form>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

