          <p className="text-[10px] text-gray-500 font-bold leading-relaxed uppercase">
            Mỗi thành viên có thể tải lên file tối đa 1GB. Hệ thống hỗ trợ nén ZIP, tệp tin thực thi và đa phương tiện.
          </p>
        </div>
      </aside>

      <div className="flex-1 space-y-6">
        {activeTab === 'feed' && !viewingGroup && (
          <>
            {renderCreatePostArea()}
            <div className="space-y-6">
              {posts.filter(p => !p.groupId).map(post => (
                <div key={post.id} className={`p-8 rounded-[2.5rem] border ${isDarkMode ? 'bg-[#0a0a0a] border-white/5 shadow-2xl' : 'bg-white border-gray-100 shadow-xl'}`}>
                  <div className="flex items-center gap-4 mb-6">
                    <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${post.authorUsername}`} className="w-12 h-12 rounded-2xl bg-gray-100" alt="" />
                    <div className="flex-1">
                      <h4 className={`text-sm font-black uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{post.author}</h4>
                      <p className="text-[10px] font-bold text-gray-500">@{post.authorUsername} • {new Date(post.timestamp).toLocaleTimeString()}</p>
                    </div>
                  </div>
                  {post.content && <p className={`text-lg leading-relaxed mb-6 font-medium ${isDarkMode ? 'text-gray-300' : 'text-gray-700'}`}>{post.content}</p>}
                  {post.fileInfo && renderFileAttachment(post.fileInfo)}
                  <div className={`pt-6 border-t flex items-center gap-6 mt-6 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
                    <button className="flex items-center gap-2 text-rose-500 font-black text-[10px] uppercase tracking-widest"><i className="fa-solid fa-heart"></i> {post.likes} Likes</button>
                    <button className="flex items-center gap-2 text-gray-400 font-black text-[10px] uppercase tracking-widest"><i className="fa-solid fa-comment"></i> {post.comments.length} Comments</button>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {activeTab === 'groups' && !viewingGroup && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {groups.map(g => (
              <div key={g.id} className={`p-8 rounded-[2.5rem] border transition-all hover:-translate-y-1 ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100'}`}>
                <div className={`${g.color} w-14 h-14 rounded-2xl flex items-center justify-center text-white mb-6`}><i className={`fa-solid ${g.icon} text-2xl`}></i></div>
                <h3 className="text-xl font-black mb-2 uppercase tracking-tighter">{g.name}</h3>
                <p className="text-sm text-gray-500 mb-6">{g.description}</p>
                <button onClick={() => setViewingGroup(g)} className="w-full py-3 rounded-xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest">Enter Sector Hub</button>
              </div>
            ))}
          </div>
        )}

        {/* Similar updates can be applied to People and Messages tabs to show the 1GB file capability */}
        {(activeTab === 'people' || activeTab === 'messages') && (
          <div className="py-20 text-center space-y-4 opacity-50">
             <i className="fa-solid fa-microchip text-4xl mb-2"></i>
             <p className="text-xs font-black uppercase tracking-widest">Sector Operational • 1GB Uplink Enabled</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Community;

import React, { useState, useEffect } from 'react';
import { APPS } from '../constants';
import { AppItem } from '../types';

const AppCard: React.FC<{ 
  app: AppItem; 
  onDelete?: (id: string) => void; 
  onUpdateUrl?: (id: string, newUrl: string) => void;
  isCustom?: boolean; 
  isDarkMode: boolean 
}> = ({ app, onDelete, onUpdateUrl, isCustom, isDarkMode }) => {
  const [isLaunching, setIsLaunching] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [tempUrl, setTempUrl] = useState(app.url);

  const handleLaunch = () => {
    if (isEditing) return;
    setIsLaunching(true);
    setTimeout(() => {
      if (app.url) {
        window.open(app.url, '_blank', 'noopener,noreferrer');
      } else {
        alert("Ứng dụng này đã được tải lên dưới dạng ZIP nhưng chưa được cấu hình URL chạy. Vui lòng cập nhật URL hoặc liên hệ quản trị viên.");
      }
      setIsLaunching(false);
    }, 800);
  };

  const saveUrl = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onUpdateUrl) onUpdateUrl(app.id, tempUrl);
    setIsEditing(false);
  };

  return (
    <div 
      onClick={handleLaunch}
      className={`group relative rounded-[2.5rem] p-8 border transition-all duration-500 hover:-translate-y-3 cursor-pointer overflow-hidden ${
      isDarkMode 
        ? 'bg-[#0a0a0a] border-white/5 shadow-[0_20px_50px_rgba(0,0,0,0.5)] hover:shadow-indigo-500/20' 
        : 'bg-white border-gray-100 shadow-xl hover:shadow-indigo-500/10'
    }`}>
      <div className={`absolute -top-20 -right-20 w-64 h-64 ${app.color || 'bg-indigo-600'} opacity-0 group-hover:opacity-10 blur-[80px] transition-opacity duration-700`}></div>

      <div className="absolute top-6 right-6 flex gap-2 z-20 opacity-0 group-hover:opacity-100 transition-all">
        <button 
          onClick={(e) => {
            e.stopPropagation();
            setIsEditing(!isEditing);
          }}
          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${
            isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-50 text-gray-500 hover:bg-black hover:text-white'
          }`}
          title="Edit Link"
        >
          <i className="fa-solid fa-link text-xs"></i>
        </button>
        {isCustom && onDelete && (
          <button 
            onClick={(e) => {
              e.stopPropagation();
              if (window.confirm('Gỡ bỏ ứng dụng này khỏi Hub?')) {
                onDelete(app.id);
              }
            }}
            className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center hover:bg-rose-500 hover:text-white ${
              isDarkMode ? 'bg-white/5 text-rose-500' : 'bg-rose-50 text-rose-500'
            }`}
          >
            <i className="fa-solid fa-trash-can text-sm"></i>
          </button>
        )}
      </div>

      <div className={`${app.color || 'bg-indigo-600'} w-16 h-16 rounded-[1.5rem] flex items-center justify-center text-white mb-8 group-hover:scale-110 group-hover:rotate-6 transition-transform duration-500 shadow-2xl relative z-10`}>
        {isLaunching ? (
          <i className="fa-solid fa-circle-notch animate-spin text-2xl"></i>
        ) : (
          <i className={`fa-solid ${app.icon || 'fa-rocket'} text-2xl`}></i>
        )}
      </div>

      <div className="space-y-4 relative z-10">
        <div className="flex items-center justify-between">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] border ${
            isDarkMode ? 'bg-white/5 text-indigo-400 border-indigo-500/20' : 'bg-indigo-50 text-indigo-600 border-indigo-100'
          }`}>
            <span className="w-1 h-1 rounded-full bg-current animate-pulse"></span>
            {app.zipFile ? 'Local ZIP Package' : (app.category || 'Module')}
          </div>

          {app.developer && (
            <div className={`text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded bg-indigo-500/10 text-indigo-500 border border-indigo-500/20`}>
              MADE BY {app.developer}
            </div>
          )}
        </div>

        <h3 className={`text-2xl font-black leading-tight tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{app.name}</h3>

        {isEditing ? (
          <div className="space-y-2 animate-in fade-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
            <p className="text-[10px] font-bold text-rose-500 uppercase tracking-widest">Update Launch URL:</p>
            <div className="flex gap-2">
              <input 
                value={tempUrl}
                onChange={e => setTempUrl(e.target.value)}
                className={`flex-1 px-4 py-2 rounded-xl text-xs font-bold outline-none border ${isDarkMode ? 'bg-black border-white/10 text-white' : 'bg-white border-gray-200'}`}
                placeholder="https://..."
              />
              <button onClick={saveUrl} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase">Save</button>
            </div>
          </div>
        ) : (
          <div className="space-y-2">
            <p className={`text-sm leading-relaxed line-clamp-2 font-medium ${isDarkMode ? 'text-gray-500' : 'text-gray-500'}`}>
              {app.description}
            </p>
            {app.zipFile && (
              <div className="flex items-center gap-2 text-[9px] font-bold text-indigo-400">
                <i className="fa-solid fa-file-zipper"></i>
                {app.zipFile.name} ({Math.round(app.zipFile.size / 1024 / 1024 * 10) / 10} MB)
              </div>
            )}
          </div>
        )}
      </div>

      <div className={`mt-10 pt-6 border-t relative z-10 transition-all ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className={`w-full py-4 text-[10px] font-black uppercase tracking-[0.2em] rounded-2xl flex items-center justify-center gap-3 transition-all ${
            isLaunching 
              ? 'bg-indigo-600 text-white'
              : (isDarkMode 
                  ? 'bg-white/5 group-hover:bg-white text-white group-hover:text-black' 
                  : 'bg-gray-50 group-hover:bg-black text-gray-500 group-hover:text-white')
          }`}>
          {isLaunching ? 'System Executing...' : 'Launch Application'}
          {!isLaunching && <i className="fa-solid fa-bolt-lightning text-xs opacity-50 group-hover:opacity-100 animate-pulse"></i>}
        </div>
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ isDarkMode: boolean }> = ({ isDarkMode }) => {
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);
  const [systemApps, setSystemApps] = useState<AppItem[]>(APPS);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedZip, setSelectedZip] = useState<File | null>(null);

  useEffect(() => {
    const storedApps = localStorage.getItem('tig_hub_custom_apps');
    if (storedApps) try { setCustomApps(JSON.parse(storedApps)); } catch (e) {}

    const storedSystem = localStorage.getItem('tig_hub_system_apps');
    if (storedSystem) try { setSystemApps(JSON.parse(storedSystem)); } catch (e) {}
  }, []);

  const handleUpdateUrl = (id: string, newUrl: string) => {
    if (systemApps.some(a => a.id === id)) {
      const updated = systemApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setSystemApps(updated);
      localStorage.setItem('tig_hub_system_apps', JSON.stringify(updated));
    } else {
      const updated = customApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
    }
  };

  // Fix: Added the missing handleDeleteApp function to the Dashboard component.
  const handleDeleteApp = (id: string) => {
    const updated = customApps.filter(a => a.id !== id);
    setCustomApps(updated);
    localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
  };

  const handleDeploy = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedZip) {
      alert("Vui lòng chọn file ZIP để tiếp tục.");
      return;
    }

    const form = e.target as any;
    const appName = form.appName.value;
    const appDesc = form.appDesc.value;

    setIsUploading(true);
    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 15;
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);

        const newApp: AppItem = {
          id: Date.now().toString(),
          name: appName,
          description: appDesc,
          url: '', // ZIP uploaded app initially has no URL
          icon: 'fa-box-archive',
          category: 'ZIP Deployment',
          color: 'bg-indigo-600',
          developer: 'TIG-Minh',
          zipFile: {
            name: selectedZip.name,
            size: selectedZip.size
          }
        };

        const updated = [newApp, ...customApps];
        setCustomApps(updated);
        localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));

        setIsUploading(false);
        setIsModalOpen(false);
        setSelectedZip(null);
        setUploadProgress(0);
      }
      setUploadProgress(progress);
    }, 200);
  };

  const displayApps = [...customApps.map(a => ({ ...a, isCustom: true })), ...systemApps];
  const filteredApps = displayApps.filter(app => {
    const name = app.name || '';
    const category = app.category || '';
    return name.toLowerCase().includes(search.toLowerCase()) ||
           category.toLowerCase().includes(search.toLowerCase());
  });

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <section className={`flex flex-col md:flex-row md:items-end justify-between gap-8 border-b pb-12 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className="space-y-4">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-black text-white'}`}>
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
            Interface: Online • Made by TIG-Minh
          </div>
          <h1 className={`text-6xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>MY COMMANDER</h1>
          <p className="text-gray-500 max-w-lg font-medium text-lg">
            Hệ sinh thái ứng dụng của <span className="text-indigo-500 font-bold">Minh</span>. Tải lên file ZIP để triển khai module mới.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-1 sm:w-80 group">
            <i className={`fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 transition-colors ${isDarkMode ? 'text-gray-600 group-focus-within:text-white' : 'text-gray-400 group-focus-within:text-black'}`}></i>
            <input
              type="text"
              placeholder="Sách ứng dụng..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className={`w-full pl-11 pr-4 py-5 rounded-[1.5rem] border-none transition-all outline-none font-bold text-sm ${
                isDarkMode ? 'bg-white/5 text-white focus:ring-2 focus:ring-indigo-500/50' : 'bg-gray-100 text-gray-900 focus:ring-2 focus:ring-black'
              }`}
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className={`px-8 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-2xl active:scale-95 ${
              isDarkMode ? 'bg-white text-black hover:bg-indigo-600 hover:text-white' : 'bg-black text-white hover:bg-indigo-600'
            }`}
          >
            <i className="fa-solid fa-cloud-arrow-up text-xs"></i>
            Deploy ZIP Module
          </button>
        </div>
      </section>

      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
        {filteredApps.map((app: any, idx) => (
          <AppCard 
            key={app.id || idx} 
            app={app} 
            isDarkMode={isDarkMode}
            isCustom={app.isCustom}
            onDelete={handleDeleteApp}
            onUpdateUrl={handleUpdateUrl}
          />
        ))}
      </section>

      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-xl animate-in fade-in duration-300">
           <div className={`w-full max-w-lg rounded-[3rem] border shadow-2xl overflow-hidden animate-in zoom-in-95 ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-200'}`}>
             <div className="p-10 border-b border-white/5 flex items-center justify-between">
                <div>
                  <h2 className={`text-2xl font-black uppercase tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Deploy Module</h2>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-[0.3em] mt-1">ZIP Deployment Protocol</p>
                </div>
                <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-full flex items-center justify-center text-gray-500 hover:bg-rose-500 hover:text-white transition-all">
                  <i className="fa-solid fa-xmark text-lg"></i>
                </button>
             </div>
             <div className="p-10 space-y-6">
                <form onSubmit={handleDeploy} className="space-y-5">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">App Name</label>
                    <input name="appName" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="E.g. Chat System" />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Upload Package (.zip only)</label>
                    <label className={`block w-full border-2 border-dashed rounded-2xl p-8 text-center cursor-pointer transition-all ${
                      selectedZip ? 'border-emerald-500 bg-emerald-500/5' : (isDarkMode ? 'border-white/10 hover:border-indigo-500' : 'border-gray-200 hover:border-black')
                    }`}>
                      <input 
                        type="file" 
                        accept=".zip" 
                        className="hidden" 
                        onChange={(e) => {
                          const file = e.target.files?.[0];
                          if (file && file.name.endsWith('.zip')) {
                            setSelectedZip(file);
                          } else if (file) {
                            alert("Chỉ chấp nhận file định dạng .zip");
                          }
                        }}
                      />
                      <i className={`fa-solid ${selectedZip ? 'fa-file-zipper text-emerald-500' : 'fa-folder-open text-gray-400'} text-3xl mb-3`}></i>
                      <p className={`text-xs font-black uppercase tracking-widest ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>
                        {selectedZip ? selectedZip.name : 'Click to select ZIP file'}
                      </p>
                      {selectedZip && <p className="text-[9px] text-emerald-500 mt-2 font-bold uppercase tracking-tighter">Package Ready: {Math.round(selectedZip.size/1024/1024*10)/10} MB</p>}
                    </label>
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Description</label>
                    <textarea name="appDesc" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all resize-none font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="Brief app overview..." rows={2} />
                  </div>

                  {isUploading && (
                    <div className="space-y-2">
                       <div className="flex justify-between text-[10px] font-black uppercase text-indigo-400 tracking-widest">
                          <span>Extracting & Deploying...</span>
                          <span>{Math.round(uploadProgress)}%</span>
                       </div>
                       <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden">
                          <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }}></div>
                       </div>
                    </div>
                  )}

                  <button 
                    type="submit" 
                    disabled={isUploading || !selectedZip}
                    className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.3em] shadow-xl hover:-translate-y-1 transition-all disabled:opacity-50"
                  >
                    Deploy Module to Hub
                  </button>
                </form>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import Dashboard from './pages/Dashboard';
import Auth from './pages/Auth';
import Landing from './pages/Landing';
import Settings from './pages/Settings';
import Community from './pages/Community';
import PresentationCreator from './pages/PresentationCreator';
import TIGLogo from './components/TIGLogo';
import { User } from './types';

const Navigation: React.FC<{ user: User | null; onLogout: () => void; isDarkMode: boolean }> = ({ user, onLogout, isDarkMode }) => {
  const location = useLocation();
  const isAuthPage = location.pathname === '/auth';

  const navItems = user ? [
    { path: '/dashboard', label: 'APPS', icon: 'fa-th-large' },
    { path: '/presentation', label: 'STUDIO', icon: 'fa-wand-magic-sparkles' },
    { path: '/community', label: 'SOCIAL', icon: 'fa-users' }
  ] : [
    { path: '/', label: 'HOME', icon: 'fa-house' }
  ];

  if (isAuthPage) return null;

  return (
    <nav className={`fixed top-0 left-0 right-0 h-16 z-[150] border-b no-print transition-colors duration-300 ${
      isDarkMode 
        ? 'bg-[#0a0a0a]/90 border-white/5 text-white backdrop-blur-md shadow-2xl shadow-black/50' 
        : 'bg-white/90 border-gray-200/50 text-gray-900 backdrop-blur-md shadow-lg shadow-gray-200/20'
    }`}>
      <div className="max-w-7xl mx-auto px-4 h-full flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Link to="/" className="flex items-center gap-3 group">
            <TIGLogo size={34} className="group-hover:rotate-[360deg] transition-transform duration-700" />
            <div className="flex flex-col leading-none">
              <span className={`text-lg font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>TIG HUB</span>
              <span className="text-[8px] font-black text-indigo-500 tracking-[0.3em] uppercase">by TIG-Minh</span>
            </div>
          </Link>
        </div>

        <div className={`flex gap-1 p-1 rounded-xl transition-colors ${isDarkMode ? 'bg-white/5' : 'bg-gray-100/50'}`}>
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`px-5 py-2 rounded-lg text-[10px] font-black tracking-widest transition-all flex items-center gap-2 ${
                location.pathname === item.path 
                  ? (isDarkMode ? 'bg-indigo-600 text-white shadow-md' : 'bg-black text-white shadow-md')
                  : (isDarkMode ? 'text-gray-400 hover:text-white' : 'text-gray-500 hover:text-gray-900')
              }`}
            >
              <i className={`fa-solid ${item.icon} text-xs`}></i>
              <span className="hidden xs:inline">{item.label}</span>
            </Link>
          ))}
        </div>

        <div className="flex items-center gap-3">
          {user ? (
            <>
              <div className="hidden sm:flex flex-col items-end">
                <span className={`text-[10px] font-black leading-none ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{user.name.toUpperCase()}</span>
                <span className="text-[8px] font-bold text-indigo-500 uppercase tracking-widest mt-0.5">Verified User</span>
              </div>
              <div className="relative group">
                <div className="p-1 cursor-pointer">
                  <button className={`w-10 h-10 rounded-xl border-2 p-0.5 overflow-hidden transition-all group-hover:scale-110 active:scale-95 ${isDarkMode ? 'border-white/20 bg-black' : 'border-black bg-white'}`}>
                    <img 
                      src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} 
                      alt="Profile" 
                      className="w-full h-full rounded-lg object-cover"
                    />
                  </button>
                </div>

                <div className="absolute right-0 top-full pt-2 w-52 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-300 transform translate-y-2 group-hover:translate-y-0 z-[160]">
                  <div className={`rounded-2xl shadow-2xl border py-2 ${isDarkMode ? 'bg-[#0f0f0f] border-white/10' : 'bg-white border-gray-200'}`}>
                    <div className={`px-4 py-3 border-b ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
                      <p className={`text-xs font-black uppercase tracking-wider ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{user.name}</p>
                      <p className="text-[10px] text-gray-500">@{user.username}</p>
                    </div>
                    <div className="p-2 space-y-1">
                      <Link 
                        to="/settings"
                        className={`w-full text-left px-4 py-3 text-[10px] font-black rounded-xl flex items-center gap-3 transition-all uppercase tracking-widest ${
                          isDarkMode ? 'text-gray-400 hover:bg-white/5 hover:text-white' : 'text-gray-500 hover:bg-gray-50 hover:text-black'
                        }`}
                      >
                        <i className="fa-solid fa-gear text-xs"></i>
                        Settings
                      </Link>
                      <button 
                        onClick={onLogout}
                        className="w-full text-left px-4 py-3 text-[10px] font-black text-rose-500 hover:bg-rose-500 hover:text-white rounded-xl flex items-center gap-3 transition-all uppercase tracking-widest"
                      >
                        <i className="fa-solid fa-power-off text-xs"></i>
                        Disconnect
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </>
          ) : (
            <Link 
              to="/auth"
              className="px-6 py-2.5 bg-black text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-xl shadow-black/10 active:scale-95"
            >
              Sign In
            </Link>
          )}
        </div>
      </div>
    </nav>
  );
};

const MainContent: React.FC = () => {
  const location = useLocation();
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('tig_hub_theme');
    return saved === 'dark';
  });

  useEffect(() => {
    const session = localStorage.getItem('tig_hub_session');
    if (session) {
      try {
        setUser(JSON.parse(session));
      } catch (e) {
        console.error("Failed to parse session", e);
      }
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    if (isDarkMode) {
      document.body.classList.add('dark');
      document.body.style.backgroundColor = '#050505';
    } else {
      document.body.classList.remove('dark');
      document.body.style.backgroundColor = '#fcfcfc';
    }
    localStorage.setItem('tig_hub_theme', isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('tig_hub_session', JSON.stringify(newUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('tig_hub_session');
  };

  const toggleTheme = (dark: boolean) => {
    setIsDarkMode(dark);
  };

  if (loading) return (
    <div className={`min-h-screen flex items-center justify-center ${isDarkMode ? 'bg-[#050505]' : 'bg-white'}`}>
      <div className="flex flex-col items-center gap-4">
        <TIGLogo size={80} className="animate-spin duration-[3s]" />
        <span className="text-[10px] font-black tracking-[0.5em] text-gray-400 animate-pulse uppercase">Syncing Hub...</span>
      </div>
    </div>
  );

  const isLandingPage = location.pathname === '/';

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-[#050505] text-white' : 'bg-[#fcfcfc] text-gray-900'}`}>
      <Navigation user={user} onLogout={handleLogout} isDarkMode={isDarkMode} />
      <main className={`max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 ${isLandingPage ? '' : 'pt-32 pb-20'}`}>
        <Routes>
          <Route path="/" element={<Landing />} />
          <Route 
            path="/auth" 
            element={user ? <Navigate to="/dashboard" /> : <Auth onLogin={handleLogin} />} 
          />
          <Route 
            path="/dashboard" 
            element={user ? <Dashboard isDarkMode={isDarkMode} /> : <Navigate to="/auth" />} 
          />
          <Route 
            path="/presentation" 
            element={user ? <PresentationCreator isDarkMode={isDarkMode} /> : <Navigate to="/auth" />} 
          />
          <Route 
            path="/community" 
            element={user ? <Community isDarkMode={isDarkMode} user={user} /> : <Navigate to="/auth" />} 
          />
          <Route 
            path="/settings" 
            element={user ? <Settings isDarkMode={isDarkMode} onThemeChange={toggleTheme} /> : <Navigate to="/auth" />} 
          />
        </Routes>
      </main>

      <footer className={`py-12 border-t text-center no-print ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className="flex flex-col items-center gap-2">
          <TIGLogo size={24} className="grayscale opacity-20" />
          <p className="text-[9px] font-black text-gray-400 uppercase tracking-[0.4em]">
            © 2025 TIG Hub Studio • Made by TIG-Minh
          </p>
        </div>
      </footer>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <HashRouter>
      <MainContent />
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { APPS } from '../constants';
import { AppItem } from '../types';

const AppCard: React.FC<{ 
  app: AppItem; 
  onDelete?: (id: string) => void; 
  onUpdateUrl?: (id: string, newUrl: string) => void;
  isCustom?: boolean; 
  isDarkMode: boolean 
}> = ({ app, onDelete, onUpdateUrl, isCustom, isDarkMode }) => {
  const [isLaunching, setIsLaunching] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [tempUrl, setTempUrl] = useState(app.url);

  const handleLaunch = () => {
    if (isEditing) return;

    if (!app.url) {
      setIsEditing(true);
      return;
    }

    setIsLaunching(true);
    setTimeout(() => {
      window.open(app.url, '_blank', 'noopener,noreferrer');
      setIsLaunching(false);
    }, 800);
  };

  const saveUrl = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onUpdateUrl) onUpdateUrl(app.id, tempUrl);
    setIsEditing(false);
  };

  return (
    <div 
      onClick={handleLaunch}
      className={`group relative rounded-[2.5rem] p-8 border transition-all duration-500 hover:-translate-y-3 cursor-pointer overflow-hidden ${
      isDarkMode 
        ? 'bg-[#0a0a0a] border-white/5 shadow-[0_20px_50px_rgba(0,0,0,0.5)] hover:shadow-indigo-500/20' 
        : 'bg-white border-gray-100 shadow-xl hover:shadow-indigo-500/10'
    }`}>
      <div className={`absolute -top-20 -right-20 w-64 h-64 ${app.color || 'bg-indigo-600'} opacity-0 group-hover:opacity-10 blur-[80px] transition-opacity duration-700`}></div>

      <div className="absolute top-6 right-6 flex gap-2 z-20 opacity-0 group-hover:opacity-100 transition-all">
        <button 
          onClick={(e) => {
            e.stopPropagation();
            setIsEditing(!isEditing);
          }}
          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${
            isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-50 text-gray-500 hover:bg-black hover:text-white'
          }`}
          title="Sửa Link"
        >
          <i className="fa-solid fa-link text-xs"></i>
        </button>
        {isCustom && onDelete && (
          <button 
            onClick={(e) => {
              e.stopPropagation();
              if (window.confirm('Gỡ bỏ ứng dụng này khỏi Hub?')) {
                onDelete(app.id);
              }
            }}
            className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center hover:bg-rose-500 hover:text-white ${
              isDarkMode ? 'bg-white/5 text-rose-500' : 'bg-rose-50 text-rose-500'
            }`}
          >
            <i className="fa-solid fa-trash-can text-sm"></i>
          </button>
        )}
      </div>

      <div className={`${app.color || 'bg-indigo-600'} w-16 h-16 rounded-[1.5rem] flex items-center justify-center text-white mb-8 group-hover:scale-110 group-hover:rotate-6 transition-transform duration-500 shadow-2xl relative z-10`}>
        {isLaunching ? (
          <i className="fa-solid fa-circle-notch animate-spin text-2xl"></i>
        ) : (
          <i className={`fa-solid ${app.icon || 'fa-rocket'} text-2xl`}></i>
        )}
      </div>

      <div className="space-y-4 relative z-10">
        <div className="flex items-center justify-between">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] border ${
            isDarkMode ? 'bg-white/5 text-indigo-400 border-indigo-500/20' : 'bg-indigo-50 text-indigo-600 border-indigo-100'
          }`}>
            <span className="w-1 h-1 rounded-full bg-current animate-pulse"></span>
            {app.zipFile ? 'Local Package' : (app.category || 'Module')}
          </div>

          {app.developer && (
            <div className={`text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded bg-indigo-500/10 text-indigo-500 border border-indigo-500/20`}>
              MADE BY {app.developer}
            </div>
          )}
        </div>

        <h3 className={`text-2xl font-black leading-tight tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{app.name}</h3>

        {isEditing ? (
          <div className="space-y-2 animate-in fade-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
            <p className="text-[10px] font-bold text-rose-500 uppercase tracking-widest">Update Launch URL:</p>
            <div className="flex gap-2">
              <input 
                autoFocus
                value={tempUrl}
                onChange={e => setTempUrl(e.target.value)}
                className={`flex-1 px-4 py-2 rounded-xl text-xs font-bold outline-none border ${isDarkMode ? 'bg-black border-white/10 text-white' : 'bg-white border-gray-200'}`}
                placeholder="https://..."
              />
              <button onClick={saveUrl} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase">Save</button>
            </div>
          </div>
        ) : (
          <div className="space-y-2">
            <p className={`text-sm leading-relaxed line-clamp-2 font-medium ${isDarkMode ? 'text-gray-500' : 'text-gray-500'}`}>
              {app.description}
            </p>
            {app.zipFile && (
              <div className="flex items-center gap-2 text-[9px] font-bold text-indigo-400">
                <i className="fa-solid fa-file-zipper"></i>
                {app.zipFile.name} ({Math.round(app.zipFile.size / 1024 / 1024 * 10) / 10} MB)
              </div>
            )}
            {!app.url && !isEditing && (
              <p className="text-[9px] font-black text-rose-500 uppercase animate-pulse">
                <i className="fa-solid fa-triangle-exclamation mr-1"></i> Missing Launch URL
              </p>
            )}
          </div>
        )}
      </div>

      <div className={`mt-10 pt-6 border-t relative z-10 transition-all ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className={`w-full py-4 text-[10px] font-black uppercase tracking-[0.2em] rounded-2xl flex items-center justify-center gap-3 transition-all ${
            isLaunching 
              ? 'bg-indigo-600 text-white'
              : (isDarkMode 
                  ? 'bg-white/5 group-hover:bg-white text-white group-hover:text-black' 
                  : 'bg-gray-50 group-hover:bg-black text-gray-500 group-hover:text-white')
          }`}>
          {isLaunching ? 'System Executing...' : (!app.url ? 'Configure URL First' : 'Launch Application')}
          {!isLaunching && <i className="fa-solid fa-bolt-lightning text-xs opacity-50 group-hover:opacity-100 animate-pulse"></i>}
        </div>
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ isDarkMode: boolean }> = ({ isDarkMode }) => {
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);
  const [systemApps, setSystemApps] = useState<AppItem[]>(APPS);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedZip, setSelectedZip] = useState<File | null>(null);

  useEffect(() => {
    const storedApps = localStorage.getItem('tig_hub_custom_apps');
    if (storedApps) try { setCustomApps(JSON.parse(storedApps)); } catch (e) {}

    const storedSystem = localStorage.getItem('tig_hub_system_apps');
    if (storedSystem) try { setSystemApps(JSON.parse(storedSystem)); } catch (e) {}
  }, []);

  const handleUpdateUrl = (id: string, newUrl: string) => {
    if (systemApps.some(a => a.id === id)) {
      const updated = systemApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setSystemApps(updated);
      localStorage.setItem('tig_hub_system_apps', JSON.stringify(updated));
    } else {
      const updated = customApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
    }
  };

  const handleDeleteApp = (id: string) => {
    const updated = customApps.filter(a => a.id !== id);
    setCustomApps(updated);
    localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
  };

  const handleDeploy = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedZip) {
      alert("Vui lòng chọn file ZIP.");
      return;
    }

    const form = e.target as any;
    const appName = form.appName.value;
    const appDesc = form.appDesc.value;
    const appUrl = form.appUrl.value;

    setIsUploading(true);
    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 10;
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);

        const newApp: AppItem = {
          id: Date.now().toString(),
          name: appName,
          description: appDesc,
          url: appUrl,
          icon: 'fa-box-archive',
          category: 'ZIP Deployment',
          color: 'bg-indigo-600',
          developer: 'TIG-Minh',
          zipFile: {
            name: selectedZip.name,
            size: selectedZip.size
          }
        };

        const updated = [newApp, ...customApps];
        setCustomApps(updated);
        localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));

        setIsUploading(false);
        setIsModalOpen(false);
        setSelectedZip(null);
        setUploadProgress(0);
      }
      setUploadProgress(progress);
    }, 150);
  };

  const displayApps = [...customApps.map(a => ({ ...a, isCustom: true })), ...systemApps];
  const filteredApps = displayApps.filter(app => {
    const name = app.name || '';
    const category = app.category || '';
    return name.toLowerCase().includes(search.toLowerCase()) ||
           category.toLowerCase().includes(search.toLowerCase());
  });

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <section className={`flex flex-col md:flex-row md:items-end justify-between gap-8 border-b pb-12 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className="space-y-4">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-black text-white'}`}>
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
            Interface: Online • Made by TIG-Minh
          </div>
          <h1 className={`text-6xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>MY COMMANDER</h1>
          <p className="text-gray-500 max-w-lg font-medium text-lg">
            Hệ sinh thái của <span className="text-indigo-500 font-bold">TIG-Minh</span>. Tải lên ZIP và nhập URL để khởi chạy ứng dụng.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-1 sm:w-80 group">
            <i className={`fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 transition-colors ${isDarkMode ? 'text-gray-600 group-focus-within:text-white' : 'text-gray-400 group-focus-within:text-black'}`}></i>
            <input
              type="text"
              placeholder="Sách ứng dụng..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className={`w-full pl-11 pr-4 py-5 rounded-[1.5rem] border-none transition-all outline-none font-bold text-sm ${
                isDarkMode ? 'bg-white/5 text-white focus:ring-2 focus:ring-indigo-500/50' : 'bg-gray-100 text-gray-900 focus:ring-2 focus:ring-black'
              }`}
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className={`px-8 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-2xl active:scale-95 ${
              isDarkMode ? 'bg-white text-black hover:bg-indigo-600 hover:text-white' : 'bg-black text-white hover:bg-indigo-600'
            }`}
          >
            <i className="fa-solid fa-cloud-arrow-up text-xs"></i>
            Deploy ZIP Module
          </button>
        </div>
      </section>

      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
        {filteredApps.map((app: any, idx) => (
          <AppCard 
            key={app.id || idx} 
            app={app} 
            isDarkMode={isDarkMode}
            isCustom={app.isCustom}
            onDelete={handleDeleteApp}
            onUpdateUrl={handleUpdateUrl}
          />
        ))}
      </section>

      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-xl animate-in fade-in duration-300">
           <div className={`w-full max-w-lg rounded-[3rem] border shadow-2xl overflow-hidden animate-in zoom-in-95 ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-200'}`}>
             <div className="p-10 border-b border-white/5 flex items-center justify-between">
                <div>
                  <h2 className={`text-2xl font-black uppercase tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Deploy Module</h2>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-[0.3em] mt-1">Upload & Configure</p>
                </div>
                <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-full flex items-center justify-center text-gray-500 hover:bg-rose-500 hover:text-white transition-all">
                  <i className="fa-solid fa-xmark text-lg"></i>
                </button>
             </div>
             <div className="p-10 space-y-6">
                <form onSubmit={handleDeploy} className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">App Name</label>
                    <input name="appName" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="E.g. My Website" />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Launch URL (Bắt buộc để chạy app)</label>
                    <input name="appUrl" type="url" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="https://myapp.vercel.app" />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Package (.zip)</label>
                    <label className={`block w-full border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${
                      selectedZip ? 'border-emerald-500 bg-emerald-500/5' : (isDarkMode ? 'border-white/10 hover:border-indigo-500' : 'border-gray-200 hover:border-black')
                    }`}>
                      <input type="file" accept=".zip" className="hidden" onChange={(e) => setSelectedZip(e.target.files?.[0] || null)} />
                      <i className={`fa-solid ${selectedZip ? 'fa-file-zipper text-emerald-500' : 'fa-folder-open text-gray-400'} text-2xl mb-2`}></i>
                      <p className="text-[10px] font-black uppercase tracking-widest">{selectedZip ? selectedZip.name : 'Select ZIP Bundle'}</p>
                    </label>
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Description</label>
                    <textarea name="appDesc" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all resize-none font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="Tool purpose..." rows={2} />
                  </div>

                  {isUploading && (
                    <div className="h-1 w-full bg-white/5 rounded-full overflow-hidden">
                      <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }}></div>
                    </div>
                  )}

                  <button type="submit" disabled={isUploading || !selectedZip} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.3em] shadow-xl hover:-translate-y-1 transition-all disabled:opacity-50">Deploy Now</button>
                </form>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { generatePresentation, generateImageForSlide } from '../services/geminiService';
import { Presentation, Slide } from '../types';

const PresentationCreator: React.FC<{ isDarkMode: boolean }> = ({ isDarkMode }) => {
  const [topic, setTopic] = useState('');
  const [style, setStyle] = useState('Professional');
  const [isGenerating, setIsGenerating] = useState(false);
  const [presentation, setPresentation] = useState<Presentation | null>(null);
  const [activeSlide, setActiveSlide] = useState(0);
  const [generatingImages, setGeneratingImages] = useState<Record<string, boolean>>({});

  const handleGenerate = async () => {
    if (!topic) return;
    setIsGenerating(true);
    try {
      const result = await generatePresentation(topic, style);
      setPresentation(result);
      setActiveSlide(0);
    } catch (error) {
      console.error(error);
      alert("Hệ thống AI đang bận, vui lòng thử lại sau.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenImage = async (slideId: string, title: string, content: string[]) => {
    setGeneratingImages(prev => ({ ...prev, [slideId]: true }));
    try {
      const imageUrl = await generateImageForSlide(title, content.join(', '));
      if (presentation) {
        const updatedSlides = presentation.slides.map(s => 
          s.id === slideId ? { ...s, imageUrl } : s
        );
        setPresentation({ ...presentation, slides: updatedSlides });
      }
    } catch (error) {
      console.error(error);
    } finally {
      setGeneratingImages(prev => ({ ...prev, [slideId]: false }));
    }
  };

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className={`border-b pb-12 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] mb-4 ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-black text-white'}`}>
          <i className="fa-solid fa-wand-magic-sparkles"></i> AI Presentation Studio • Made by TIG-Minh
        </div>
        <h1 className={`text-6xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>SLIDE ARCHITECT</h1>
        <p className="text-gray-500 mt-4 max-w-lg font-medium">Nhập chủ đề để AI tự động thiết kế nội dung và hình ảnh bài thuyết trình cho bạn.</p>
      </header>

      {!presentation ? (
        <section className={`p-12 rounded-[3rem] border shadow-2xl ${isDarkMode ? 'bg-[#0a0a0a] border-white/5' : 'bg-white border-gray-100'}`}>
          <div className="max-w-xl mx-auto space-y-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Presentation Topic</label>
              <input 
                value={topic}
                onChange={e => setTopic(e.target.value)}
                placeholder="E.g. The Future of AI in Education..."
                className={`w-full px-8 py-5 rounded-3xl outline-none border transition-all text-lg font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200 focus:border-black'}`}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
               {['Professional', 'Futuristic', 'Minimalist', 'Creative'].map(s => (
                 <button 
                  key={s}
                  onClick={() => setStyle(s)}
                  className={`py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all border ${
                    style === s 
                      ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' 
                      : (isDarkMode ? 'bg-white/5 text-gray-400 border-white/5' : 'bg-gray-50 text-gray-500 border-gray-100')
                  }`}
                 >
                   {s}
                 </button>
               ))}
            </div>

            <button 
              onClick={handleGenerate}
              disabled={isGenerating || !topic}
              className={`w-full py-6 rounded-3xl bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.3em] shadow-xl hover:-translate-y-1 transition-all active:scale-95 disabled:opacity-50`}
            >
              {isGenerating ? (
                <span className="flex items-center justify-center gap-3">
                  <i className="fa-solid fa-circle-notch animate-spin"></i>
                  Architecting Slides...
                </span>
              ) : 'Generate Masterpiece'}
            </button>
          </div>
        </section>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          <aside className="lg:col-span-3 space-y-3">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-[10px] font-black uppercase text-gray-500 tracking-widest">Outline</h3>
              <button onClick={() => setPresentation(null)} className="text-[10px] font-black text-rose-500 uppercase tracking-widest hover:underline">New</button>
            </div>
            {presentation.slides.map((slide, idx) => (
              <button
                key={slide.id}
                onClick={() => setActiveSlide(idx)}
                className={`w-full p-5 rounded-2xl text-left transition-all border ${
                  activeSlide === idx 
                    ? (isDarkMode ? 'bg-white text-black border-white' : 'bg-black text-white border-black')
                    : (isDarkMode ? 'bg-white/5 border-white/5 text-gray-400' : 'bg-gray-50 border-gray-100 text-gray-600')
                }`}
              >
                <div className="text-[9px] font-black opacity-50 mb-1">SLIDE {idx + 1}</div>
                <div className="text-xs font-black uppercase tracking-tighter truncate">{slide.title}</div>
              </button>
            ))}
          </aside>

          <main className="lg:col-span-9 space-y-6">
            <div className={`relative aspect-video rounded-[3rem] border shadow-2xl overflow-hidden flex flex-col ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-100'}`}>
               {presentation.slides[activeSlide].imageUrl ? (
                 <img src={presentation.slides[activeSlide].imageUrl} className="absolute inset-0 w-full h-full object-cover opacity-30 blur-[2px]" alt="" />
               ) : null}

               <div className="relative z-10 flex-1 p-16 flex flex-col justify-center">
                  <div className="mb-4 inline-flex items-center gap-2 px-3 py-1 bg-indigo-600 rounded-full text-[9px] font-black text-white uppercase tracking-widest">
                    Slide {activeSlide + 1}
                  </div>
                  <h2 className="text-5xl font-black tracking-tighter uppercase mb-8 leading-none">{presentation.slides[activeSlide].title}</h2>
                  <ul className="space-y-4">
                    {presentation.slides[activeSlide].content.map((item, i) => (
                      <li key={i} className="flex items-start gap-4 text-xl font-medium opacity-80">
                        <span className="w-2 h-2 rounded-full bg-indigo-500 mt-3 shrink-0"></span>
                        {item}
                      </li>
                    ))}
                  </ul>
               </div>

               <div className="relative z-10 p-10 border-t border-white/5 bg-black/40 backdrop-blur-md flex items-center justify-between">
                  <div className="flex gap-4">
                    <button 
                      onClick={() => handleGenImage(presentation.slides[activeSlide].id, presentation.slides[activeSlide].title, presentation.slides[activeSlide].content)}
                      disabled={generatingImages[presentation.slides[activeSlide].id]}
                      className="px-6 py-3 rounded-xl bg-white/10 hover:bg-white text-[10px] font-black uppercase text-white hover:text-black transition-all flex items-center gap-2"
                    >
                      {generatingImages[presentation.slides[activeSlide].id] ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-image"></i>}
                      {presentation.slides[activeSlide].imageUrl ? 'Regenerate Background' : 'Generate Visual'}
                    </button>
                  </div>
                  <div className="text-[10px] font-black uppercase tracking-[0.4em] opacity-30">TIG Studio System</div>
               </div>
            </div>

            <div className={`p-8 rounded-[2rem] border ${isDarkMode ? 'bg-white/5 border-white/5' : 'bg-gray-50 border-gray-100'}`}>
              <h4 className="text-[10px] font-black uppercase text-indigo-500 tracking-widest mb-4">Speaker Notes</h4>
              <p className="text-sm font-medium leading-relaxed opacity-60 italic">{presentation.slides[activeSlide].speakerNotes}</p>
            </div>
          </main>
        </div>
      )}
    </div>
  );
};

export default PresentationCreator;

