import React, { useState, useEffect } from 'react';
import { APPS } from '../constants';
import { AppItem } from '../types';

const LocalAppRunner: React.FC<{ app: AppItem; onClose: () => void; isDarkMode: boolean }> = ({ app, onClose, isDarkMode }) => {
  const [bootStage, setBootStage] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);

  useEffect(() => {
    const sequence = [
      `Initializing Virtual Container for ${app.name}...`,
      "Allocating memory resources...",
      "Extracting ZIP package contents...",
      "Mounting virtual file system...",
      "Starting local host service at port 8080...",
      "Application Bridge: CONNECTED",
      "Ready to execute."
    ];

    let current = 0;
    const interval = setInterval(() => {
      if (current < sequence.length) {
        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${sequence[current]}`]);
        setBootStage(prev => prev + (100 / sequence.length));
        current++;
      } else {
        clearInterval(interval);
      }
    }, 400);

    return () => clearInterval(interval);
  }, [app.name]);

  return (
    <div className="fixed inset-0 z-[300] bg-black/95 backdrop-blur-3xl flex flex-col animate-in fade-in duration-500">
      {/* Top Bar */}
      <div className="h-14 border-b border-white/10 flex items-center justify-between px-6 bg-black/50">
        <div className="flex items-center gap-4">
          <div className={`${app.color} w-8 h-8 rounded-lg flex items-center justify-center text-white text-xs`}>
            <i className={`fa-solid ${app.icon || 'fa-microchip'}`}></i>
          </div>
          <div>
            <h3 className="text-[10px] font-black text-white uppercase tracking-widest leading-none">{app.name}</h3>
            <p className="text-[8px] text-emerald-500 font-bold uppercase tracking-widest mt-1">
              <span className="inline-block w-1 h-1 rounded-full bg-emerald-500 animate-ping mr-1"></span>
              Virtual Instance Running
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden md:flex items-center gap-4 px-4 py-1.5 rounded-full bg-white/5 border border-white/5 mr-4">
            <div className="flex flex-col items-end">
              <span className="text-[8px] font-black text-gray-500 uppercase">Memory Usage</span>
              <span className="text-[10px] font-bold text-white">124.5 MB</span>
            </div>
            <div className="w-px h-6 bg-white/10"></div>
            <div className="flex flex-col items-end">
              <span className="text-[8px] font-black text-gray-500 uppercase">Latency</span>
              <span className="text-[10px] font-bold text-emerald-400">0.2ms</span>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="px-6 py-2 bg-rose-500 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg shadow-rose-500/20"
          >
            Terminate Session
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex overflow-hidden">
        {/* Terminal/Log Sidebar */}
        <div className="w-80 border-r border-white/10 bg-black/40 p-6 hidden lg:flex flex-col gap-4 font-mono">
          <h4 className="text-[9px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-2">
            <i className="fa-solid fa-terminal text-indigo-500"></i>
            Execution Logs
          </h4>
          <div className="flex-1 overflow-y-auto space-y-2 scrollbar-hide">
            {logs.map((log, i) => (
              <div key={i} className="text-[10px] text-gray-400 leading-relaxed break-words animate-in slide-in-from-left-2">
                {log}
              </div>
            ))}
          </div>
        </div>

        {/* Application Viewport */}
        <div className="flex-1 relative bg-[#050505] overflow-hidden p-8 flex items-center justify-center">
          {bootStage < 100 ? (
            <div className="w-full max-w-md space-y-8 text-center">
              <div className="relative inline-block">
                 <div className="absolute inset-0 bg-indigo-500/20 blur-3xl rounded-full"></div>
                 <i className={`fa-solid ${app.icon || 'fa-rocket'} text-7xl text-white relative animate-bounce`}></i>
              </div>
              <div className="space-y-3">
                <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.5em] animate-pulse">Launching Virtual App</p>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${bootStage}%` }}></div>
                </div>
                <p className="text-[9px] font-bold text-gray-600 uppercase">TIG Virtual Engine v2.5.0</p>
              </div>
            </div>
          ) : (
            <div className="w-full h-full rounded-[2rem] border border-white/5 bg-[#0a0a0a] shadow-2xl flex flex-col items-center justify-center p-12 text-center animate-in zoom-in-95 duration-700">
               <div className="space-y-6">
                 <i className="fa-solid fa-check-circle text-7xl text-emerald-500"></i>
                 <h2 className="text-3xl font-black text-white tracking-tighter uppercase">Application Executed Successfully</h2>
                 <p className="text-gray-500 max-w-sm mx-auto font-medium">
                   Ứng dụng từ gói <b>{app.zipFile?.name}</b> đang chạy trong chế độ Sandbox bảo mật của TIG Hub. 
                   <br/><br/>
                   <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest bg-indigo-500/10 px-4 py-2 rounded-full">
                     Internal Service Running on Port 8080
                   </span>
                 </p>
                 <div className="pt-8 grid grid-cols-2 gap-4">
                    <div className="p-4 rounded-2xl bg-white/5 border border-white/5">
                       <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-1">Status</p>
                       <p className="text-xs font-bold text-white">READY</p>
                    </div>
                    <div className="p-4 rounded-2xl bg-white/5 border border-white/5">
                       <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest mb-1">Uptime</p>
                       <p className="text-xs font-bold text-white">00:04:12</p>
                    </div>
                 </div>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const AppCard: React.FC<{ 
  app: AppItem; 
  onDelete?: (id: string) => void; 
  onUpdateUrl?: (id: string, newUrl: string) => void;
  onLaunchLocal?: (app: AppItem) => void;
  isCustom?: boolean; 
  isDarkMode: boolean 
}> = ({ app, onDelete, onUpdateUrl, onLaunchLocal, isCustom, isDarkMode }) => {
  const [isLaunching, setIsLaunching] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [tempUrl, setTempUrl] = useState(app.url || '');

  const handleLaunch = () => {
    if (isEditing) return;

    // Nếu không có URL nhưng có file ZIP, chạy local
    if (!app.url && app.zipFile && onLaunchLocal) {
      setIsLaunching(true);
      setTimeout(() => {
        onLaunchLocal(app);
        setIsLaunching(false);
      }, 800);
      return;
    }

    // Nếu không có cả URL lẫn ZIP
    if (!app.url) {
      setIsEditing(true);
      return;
    }

    setIsLaunching(true);
    setTimeout(() => {
      window.open(app.url, '_blank', 'noopener,noreferrer');
      setIsLaunching(false);
    }, 800);
  };

  const saveUrl = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onUpdateUrl) onUpdateUrl(app.id, tempUrl);
    setIsEditing(false);
  };

  return (
    <div 
      onClick={handleLaunch}
      className={`group relative rounded-[2.5rem] p-8 border transition-all duration-500 hover:-translate-y-3 cursor-pointer overflow-hidden ${
      isDarkMode 
        ? 'bg-[#0a0a0a] border-white/5 shadow-[0_20px_50px_rgba(0,0,0,0.5)] hover:shadow-indigo-500/20' 
        : 'bg-white border-gray-100 shadow-xl hover:shadow-indigo-500/10'
    }`}>
      <div className={`absolute -top-20 -right-20 w-64 h-64 ${app.color || 'bg-indigo-600'} opacity-0 group-hover:opacity-10 blur-[80px] transition-opacity duration-700`}></div>

      <div className="absolute top-6 right-6 flex gap-2 z-20 opacity-0 group-hover:opacity-100 transition-all">
        <button 
          onClick={(e) => {
            e.stopPropagation();
            setIsEditing(!isEditing);
          }}
          className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center ${
            isDarkMode ? 'bg-white/5 text-gray-400 hover:text-white' : 'bg-gray-50 text-gray-500 hover:bg-black hover:text-white'
          }`}
          title="Sửa Link"
        >
          <i className="fa-solid fa-link text-xs"></i>
        </button>
        {isCustom && onDelete && (
          <button 
            onClick={(e) => {
              e.stopPropagation();
              if (window.confirm('Gỡ bỏ ứng dụng này khỏi Hub?')) {
                onDelete(app.id);
              }
            }}
            className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center hover:bg-rose-500 hover:text-white ${
              isDarkMode ? 'bg-white/5 text-rose-500' : 'bg-rose-50 text-rose-500'
            }`}
          >
            <i className="fa-solid fa-trash-can text-sm"></i>
          </button>
        )}
      </div>

      <div className={`${app.color || 'bg-indigo-600'} w-16 h-16 rounded-[1.5rem] flex items-center justify-center text-white mb-8 group-hover:scale-110 group-hover:rotate-6 transition-transform duration-500 shadow-2xl relative z-10`}>
        {isLaunching ? (
          <i className="fa-solid fa-circle-notch animate-spin text-2xl"></i>
        ) : (
          <i className={`fa-solid ${app.zipFile && !app.url ? 'fa-box-archive' : (app.icon || 'fa-rocket')} text-2xl`}></i>
        )}
      </div>

      <div className="space-y-4 relative z-10">
        <div className="flex items-center justify-between">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-[0.2em] border ${
            isDarkMode ? 'bg-white/5 text-indigo-400 border-indigo-500/20' : 'bg-indigo-50 text-indigo-600 border-indigo-100'
          }`}>
            <span className="w-1 h-1 rounded-full bg-current animate-pulse"></span>
            {app.zipFile && !app.url ? 'Local Virtual App' : (app.category || 'Module')}
          </div>

          {app.developer && (
            <div className={`text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded bg-indigo-500/10 text-indigo-500 border border-indigo-500/20`}>
              MADE BY {app.developer}
            </div>
          )}
        </div>

        <h3 className={`text-2xl font-black leading-tight tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>{app.name}</h3>

        {isEditing ? (
          <div className="space-y-2 animate-in fade-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
            <p className="text-[10px] font-bold text-rose-500 uppercase tracking-widest">Update Launch URL:</p>
            <div className="flex gap-2">
              <input 
                autoFocus
                value={tempUrl}
                onChange={e => setTempUrl(e.target.value)}
                className={`flex-1 px-4 py-2 rounded-xl text-xs font-bold outline-none border ${isDarkMode ? 'bg-black border-white/10 text-white' : 'bg-white border-gray-200'}`}
                placeholder="https://..."
              />
              <button onClick={saveUrl} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase">Save</button>
            </div>
          </div>
        ) : (
          <div className="space-y-2">
            <p className={`text-sm leading-relaxed line-clamp-2 font-medium ${isDarkMode ? 'text-gray-500' : 'text-gray-500'}`}>
              {app.description}
            </p>
            {app.zipFile && (
              <div className="flex items-center gap-2 text-[9px] font-bold text-indigo-400 mt-2 bg-indigo-500/5 px-3 py-1.5 rounded-lg border border-indigo-500/10 w-fit">
                <i className="fa-solid fa-file-zipper"></i>
                {app.zipFile.name} ({Math.round(app.zipFile.size / 1024 / 1024 * 10) / 10} MB)
              </div>
            )}
            {!app.url && !app.zipFile && !isEditing && (
              <p className="text-[9px] font-black text-rose-500 uppercase animate-pulse">
                <i className="fa-solid fa-triangle-exclamation mr-1"></i> No Source Found
              </p>
            )}
          </div>
        )}
      </div>

      <div className={`mt-10 pt-6 border-t relative z-10 transition-all ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className={`w-full py-4 text-[10px] font-black uppercase tracking-[0.2em] rounded-2xl flex items-center justify-center gap-3 transition-all ${
            isLaunching 
              ? 'bg-indigo-600 text-white'
              : (isDarkMode 
                  ? 'bg-white/5 group-hover:bg-white text-white group-hover:text-black' 
                  : 'bg-gray-50 group-hover:bg-black text-gray-500 group-hover:text-white')
          }`}>
          {isLaunching ? 'System Executing...' : (app.zipFile && !app.url ? 'Launch Local Instance' : (!app.url ? 'Configure URL First' : 'Launch Application'))}
          {!isLaunching && <i className="fa-solid fa-bolt-lightning text-xs opacity-50 group-hover:opacity-100 animate-pulse"></i>}
        </div>
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ isDarkMode: boolean }> = ({ isDarkMode }) => {
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);
  const [systemApps, setSystemApps] = useState<AppItem[]>(APPS);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [selectedZip, setSelectedZip] = useState<File | null>(null);
  const [runningApp, setRunningApp] = useState<AppItem | null>(null);

  useEffect(() => {
    const storedApps = localStorage.getItem('tig_hub_custom_apps');
    if (storedApps) try { setCustomApps(JSON.parse(storedApps)); } catch (e) {}

    const storedSystem = localStorage.getItem('tig_hub_system_apps');
    if (storedSystem) try { setSystemApps(JSON.parse(storedSystem)); } catch (e) {}
  }, []);

  const handleUpdateUrl = (id: string, newUrl: string) => {
    if (systemApps.some(a => a.id === id)) {
      const updated = systemApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setSystemApps(updated);
      localStorage.setItem('tig_hub_system_apps', JSON.stringify(updated));
    } else {
      const updated = customApps.map(a => a.id === id ? { ...a, url: newUrl } : a);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
    }
  };

  const handleDeleteApp = (id: string) => {
    const updated = customApps.filter(a => a.id !== id);
    setCustomApps(updated);
    localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));
  };

  const handleDeploy = (e: React.FormEvent) => {
    e.preventDefault();
    const form = e.target as any;
    const appName = form.appName.value;
    const appDesc = form.appDesc.value;
    const appUrl = form.appUrl.value;

    if (!selectedZip && !appUrl) {
      alert("Bạn phải cung cấp ít nhất một file ZIP hoặc một Launch URL.");
      return;
    }

    setIsUploading(true);
    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 15;
      if (progress >= 100) {
        progress = 100;
        clearInterval(interval);

        const newApp: AppItem = {
          id: Date.now().toString(),
          name: appName,
          description: appDesc,
          url: appUrl || undefined,
          icon: selectedZip && !appUrl ? 'fa-box-archive' : 'fa-rocket',
          category: selectedZip ? 'ZIP Deployment' : 'External Link',
          color: 'bg-indigo-600',
          developer: 'TIG-Minh',
          zipFile: selectedZip ? {
            name: selectedZip.name,
            size: selectedZip.size
          } : undefined
        };

        const updated = [newApp, ...customApps];
        setCustomApps(updated);
        localStorage.setItem('tig_hub_custom_apps', JSON.stringify(updated));

        setIsUploading(false);
        setIsModalOpen(false);
        setSelectedZip(null);
        setUploadProgress(0);
      }
      setUploadProgress(progress);
    }, 100);
  };

  const displayApps = [...customApps.map(a => ({ ...a, isCustom: true })), ...systemApps];
  const filteredApps = displayApps.filter(app => {
    const name = app.name || '';
    const category = app.category || '';
    return name.toLowerCase().includes(search.toLowerCase()) ||
           category.toLowerCase().includes(search.toLowerCase());
  });

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Local App Runner Overlay */}
      {runningApp && (
        <LocalAppRunner 
          app={runningApp} 
          onClose={() => setRunningApp(null)} 
          isDarkMode={isDarkMode} 
        />
      )}

      <section className={`flex flex-col md:flex-row md:items-end justify-between gap-8 border-b pb-12 ${isDarkMode ? 'border-white/5' : 'border-gray-100'}`}>
        <div className="space-y-4">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-black text-white'}`}>
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
            TIG Execution System v2.0 • Online
          </div>
          <h1 className={`text-6xl font-black tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>COMMAND HUB</h1>
          <p className="text-gray-500 max-w-lg font-medium text-lg">
            Hệ sinh thái ứng dụng của <span className="text-indigo-500 font-bold">TIG-Minh</span>. Triển khai các Module ZIP và khởi chạy trực tiếp trên web này.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <div className="relative flex-1 sm:w-80 group">
            <i className={`fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 transition-colors ${isDarkMode ? 'text-gray-600 group-focus-within:text-white' : 'text-gray-400 group-focus-within:text-black'}`}></i>
            <input
              type="text"
              placeholder="Search Applications..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className={`w-full pl-11 pr-4 py-5 rounded-[1.5rem] border-none transition-all outline-none font-bold text-sm ${
                isDarkMode ? 'bg-white/5 text-white focus:ring-2 focus:ring-indigo-500/50' : 'bg-gray-100 text-gray-900 focus:ring-2 focus:ring-black'
              }`}
            />
          </div>
          <button 
            onClick={() => setIsModalOpen(true)}
            className={`px-8 py-5 rounded-[1.5rem] font-black text-[10px] uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-2xl active:scale-95 ${
              isDarkMode ? 'bg-white text-black hover:bg-indigo-600 hover:text-white' : 'bg-black text-white hover:bg-indigo-600'
            }`}
          >
            <i className="fa-solid fa-plus-circle text-xs"></i>
            Deploy New Module
          </button>
        </div>
      </section>

      <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
        {filteredApps.map((app: any, idx) => (
          <AppCard 
            key={app.id || idx} 
            app={app} 
            isDarkMode={isDarkMode}
            isCustom={app.isCustom}
            onDelete={handleDeleteApp}
            onUpdateUrl={handleUpdateUrl}
            onLaunchLocal={(a) => setRunningApp(a)}
          />
        ))}
        {filteredApps.length === 0 && (
          <div className="col-span-full py-20 text-center opacity-30">
            <i className="fa-solid fa-ghost text-6xl mb-4"></i>
            <p className="text-sm font-black uppercase tracking-widest">No Applications Detected</p>
          </div>
        )}
      </section>

      {isModalOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/90 backdrop-blur-xl animate-in fade-in duration-300">
           <div className={`w-full max-w-lg rounded-[3rem] border shadow-2xl overflow-hidden animate-in zoom-in-95 ${isDarkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-gray-200'}`}>
             <div className="p-10 border-b border-white/5 flex items-center justify-between">
                <div>
                  <h2 className={`text-2xl font-black uppercase tracking-tighter ${isDarkMode ? 'text-white' : 'text-gray-900'}`}>Deploy Module</h2>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-[0.3em] mt-1">Local or Remote Deployment</p>
                </div>
                <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-full flex items-center justify-center text-gray-500 hover:bg-rose-500 hover:text-white transition-all">
                  <i className="fa-solid fa-xmark text-lg"></i>
                </button>
             </div>
             <div className="p-10 space-y-6">
                <form onSubmit={handleDeploy} className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">App Name</label>
                    <input name="appName" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="E.g. My Website" />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Package (.zip) - Để chạy Local</label>
                    <label className={`block w-full border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${
                      selectedZip ? 'border-emerald-500 bg-emerald-500/5' : (isDarkMode ? 'border-white/10 hover:border-indigo-500' : 'border-gray-200 hover:border-black')
                    }`}>
                      <input type="file" accept=".zip" className="hidden" onChange={(e) => setSelectedZip(e.target.files?.[0] || null)} />
                      <i className={`fa-solid ${selectedZip ? 'fa-file-zipper text-emerald-500' : 'fa-upload text-gray-400'} text-2xl mb-2`}></i>
                      <p className="text-[10px] font-black uppercase tracking-widest">{selectedZip ? selectedZip.name : 'Upload ZIP Module'}</p>
                    </label>
                  </div>

                  <div className="space-y-1">
                    <div className="flex justify-between items-center mb-1">
                      <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest ml-1">Launch URL (Tùy chọn)</label>
                      {!selectedZip && <span className="text-[8px] font-black text-rose-500 uppercase italic">Bắt buộc nếu không có ZIP</span>}
                    </div>
                    <input name="appUrl" type="url" className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="https://myapp.vercel.app" />
                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Brief Description</label>
                    <textarea name="appDesc" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all resize-none font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="What does this module do?" rows={2} />
                  </div>

                  {isUploading && (
                    <div className="space-y-2">
                      <div className="flex justify-between text-[8px] font-black text-indigo-400 uppercase tracking-widest">
                        <span>Deploying to Hub Core...</span>
                        <span>{Math.round(uploadProgress)}%</span>
                      </div>
                      <div className="h-1 w-full bg-white/5 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }}></div>
                      </div>
                    </div>
                  )}

                  <button 
                    type="submit" 
                    disabled={isUploading} 
                    className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.3em] shadow-xl hover:-translate-y-1 transition-all disabled:opacity-50"
                  >
                    Confirm Deployment
                  </button>
                </form>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { APPS } from '../constants';
import { AppItem } from '../types';

const LocalAppRunner: React.FC<{ app: AppItem; onClose: () => void; isDarkMode: boolean }> = ({ app, onClose, isDarkMode }) => {
  const [bootStage, setBootStage] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const [isFullyReady, setIsFullyReady] = useState(false);
  const [viewMode, setViewMode] = useState<'app' | 'files'>('app');

  useEffect(() => {
    const sequence = [
      `Initializing Virtual Container for ${app.name}...`,
      "Allocating memory resources...",
      "Extracting ZIP package contents...",
      "Mounting virtual file system...",
      "Resolving dependencies from manifest.json...",
      "Starting local host service at port 8080...",
      "Injecting TIG-Minh Bridge API...",
      "Application UI Layer: READY",
      "Ready to execute."
    ];

    let current = 0;
    const interval = setInterval(() => {
      if (current < sequence.length) {
        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${sequence[current]}`]);
        setBootStage(prev => prev + (100 / sequence.length));
        current++;
      } else {
        clearInterval(interval);
        setTimeout(() => setIsFullyReady(true), 500);
      }
    }, 350);

    return () => clearInterval(interval);
  }, [app.name]);

  return (
    <div className="fixed inset-0 z-[300] bg-[#050505] flex flex-col animate-in fade-in duration-500 overflow-hidden">
      {/* OS-Style Top Bar */}
      <div className="h-12 border-b border-white/10 flex items-center justify-between px-4 bg-black/80 backdrop-blur-md">
        <div className="flex items-center gap-3">
          <div className="flex gap-1.5 mr-4">
             <div onClick={onClose} className="w-3 h-3 rounded-full bg-rose-500 cursor-pointer hover:brightness-125 transition-all"></div>
             <div className="w-3 h-3 rounded-full bg-amber-500 opacity-50"></div>
             <div className="w-3 h-3 rounded-full bg-emerald-500 opacity-50"></div>
          </div>
          <div className="flex items-center gap-2">
            <div className={`${app.color} w-6 h-6 rounded-md flex items-center justify-center text-white text-[10px]`}>
              <i className={`fa-solid ${app.icon || 'fa-microchip'}`}></i>
            </div>
            <span className="text-[10px] font-black text-white/50 uppercase tracking-widest">{app.name}</span>
          </div>
        </div>

        {isFullyReady && (
          <div className="flex bg-white/5 rounded-lg p-0.5 border border-white/5">
            <button 
              onClick={() => setViewMode('app')}
              className={`px-4 py-1 rounded-md text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'app' ? 'bg-indigo-600 text-white' : 'text-gray-500 hover:text-white'}`}
            >
              <i className="fa-solid fa-window-maximize mr-2"></i>View App
            </button>
            <button 
              onClick={() => setViewMode('files')}
