                   <div className="flex-1 h-6 bg-black/40 rounded-md border border-white/5 flex items-center px-3 gap-2">
                      <i className="fa-solid fa-lock text-[8px] text-emerald-500"></i>
                      <span className="text-[9px] text-gray-400 font-mono truncate">
                        {app.url || `tig://localhost:8080/${app.name.toLowerCase().replace(/\s+/g, '-')}`}
                      </span>
                   </div>
                </div>

                {/* The actual App Content */}
                <div className="flex-1 bg-white overflow-hidden relative">
                  {app.url ? (
                    <iframe 
                      src={app.url} 
                      className="w-full h-full border-none"
                      title={app.name}
                    />
