                    <div className="w-full h-full bg-[#f8fafc] flex flex-col items-center justify-center p-12 text-center animate-in zoom-in-95 duration-700">
                       <div className="max-w-2xl space-y-8">
                         <div className={`${app.color} w-24 h-24 rounded-[2.5rem] flex items-center justify-center text-white mx-auto shadow-2xl`}>
                            <i className={`fa-solid ${app.icon || 'fa-box-archive'} text-4xl`}></i>
