                               <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Performance</p>
                               <p className="text-sm font-bold text-black">Ultra Fast</p>
                            </div>
                            <div className="p-6 rounded-3xl bg-white border border-gray-100 shadow-sm">
                               <i className="fa-solid fa-shield-check text-indigo-500 mb-2"></i>
                               <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Security</p>
                               <p className="text-sm font-bold text-black">Sandboxed</p>
                            </div>
                            <div className="p-6 rounded-3xl bg-white border border-gray-100 shadow-sm">
                               <i className="fa-solid fa-network-wired text-indigo-500 mb-2"></i>
                               <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Endpoint</p>
