                       <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">{app.zipFile?.name}</span>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                       {[
                         { name: 'assets', icon: 'fa-folder', color: 'text-amber-400' },
                         { name: 'src', icon: 'fa-folder', color: 'text-amber-400' },
                         { name: 'index.html', icon: 'fa-file-code', color: 'text-indigo-400' },
                         { name: 'styles.css', icon: 'fa-file-code', color: 'text-sky-400' },
                         { name: 'main.js', icon: 'fa-file-code', color: 'text-amber-300' },
                         { name: 'package.json', icon: 'fa-file-lines', color: 'text-gray-400' },
                         { name: 'README.md', icon: 'fa-file-lines', color: 'text-gray-400' }
