                  </div>

                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Brief Description</label>
                    <textarea name="appDesc" required className={`w-full px-6 py-4 rounded-2xl outline-none border transition-all resize-none font-bold ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-50 border-gray-200'}`} placeholder="What does this module do?" rows={2} />
                  </div>

                  {isUploading && (
                    <div className="space-y-2">
                      <div className="flex justify-between text-[8px] font-black text-indigo-400 uppercase tracking-widest">
                        <span>Deploying to Hub Core...</span>
                        <span>{Math.round(uploadProgress)}%</span>
                      </div>
                      <div className="h-1 w-full bg-white/5 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-600 transition-all duration-300" style={{ width: `${uploadProgress}%` }}></div>
                      </div>
                    </div>
                  )}

                  <button 
                    type="submit" 
                    disabled={isUploading} 
                    className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.3em] shadow-xl hover:-translate-y-1 transition-all disabled:opacity-50"
                  >
                    Confirm Deployment
                  </button>
                </form>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

