import React, { useState, useEffect, useRef } from 'react';
import JSZip from 'jszip';
import { APPS } from '../constants';
import { AppItem } from '../types';

// Global store for zip files in the current session (since localStorage is too small for big ZIPs)
const ZIP_STORE = new Map<string, File>();

const LocalAppRunner: React.FC<{ app: AppItem; onClose: () => void; isDarkMode: boolean }> = ({ app, onClose, isDarkMode }) => {
  const [bootStage, setBootStage] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const [isFullyReady, setIsFullyReady] = useState(false);
  const [viewMode, setViewMode] = useState<'app' | 'files'>('app');
  const [appUrl, setAppUrl] = useState<string | null>(null);
  const [vfs, setVfs] = useState<{name: string, type: string}[]>([]);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const runSequence = async () => {
      setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Initializing Virtual Container...`]);

      try {
        // Step 1: Check source
        if (app.url) {
          setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] External URL detected. Pointing to source...`]);
          setAppUrl(app.url);
          setBootStage(60);
        } else {
          // Step 2: Load and Parse ZIP
          setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Loading ZIP package: ${app.zipFile?.name}...`]);
          const file = ZIP_STORE.get(app.id);

          if (!file) {
            throw new Error("Tệp ZIP không tìm thấy trong session hiện tại. Vui lòng tải lại tệp.");
          }

          setBootStage(30);
          const zip = await JSZip.loadAsync(file);

          // List files for VFS
          const files: {name: string, type: string}[] = [];
          zip.forEach((relativePath, zipEntry) => {
            files.push({ name: relativePath, type: zipEntry.dir ? 'dir' : 'file' });
          });
          setVfs(files);
          setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] VFS Mounted: ${files.length} items found.`]);

          // Step 3: Find index.html
          const entryPoint = zip.file("index.html") || zip.file(app.name.toLowerCase() + "/index.html");
          if (entryPoint) {
            setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Entry point 'index.html' found. Rendering content...`]);
            const content = await entryPoint.async("string");

            // Create a blob URL for the HTML
            // Note: This is a simplified runner. External assets (CSS/JS) inside ZIP might need path rewriting
            // for a full production environment, but this serves the "run it now" request beautifully.
            const blob = new Blob([content], { type: 'text/html' });
            setAppUrl(URL.createObjectURL(blob));
          } else {
            setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] WARNING: No 'index.html' found. Showing folder view.`]);
            setViewMode('files');
          }
        }

        setBootStage(100);
        setTimeout(() => setIsFullyReady(true), 800);

      } catch (err: any) {
        setLogs(prev => [...prev, `[ERROR] ${err.message}`]);
        setError(err.message);
      }
    };

    runSequence();

    return () => {
      if (appUrl && appUrl.startsWith('blob:')) {
        URL.revokeObjectURL(appUrl);
      }
    };
  }, [app]);

  return (
    <div className="fixed inset-0 z-[300] bg-[#050505] flex flex-col animate-in fade-in duration-500 overflow-hidden">
      {/* Top Bar Navigation */}
      <div className="h-14 border-b border-white/10 flex items-center justify-between px-6 bg-black/80 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className="flex gap-1.5 mr-2">
            <button onClick={onClose} className="w-3.5 h-3.5 rounded-full bg-rose-500 hover:brightness-125 transition-all shadow-lg shadow-rose-500/20"></button>
            <div className="w-3.5 h-3.5 rounded-full bg-amber-500/30"></div>
            <div className="w-3.5 h-3.5 rounded-full bg-emerald-500/30"></div>
          </div>
          <div className="flex items-center gap-3 border-l border-white/10 pl-4">
            <div className={`${app.color} w-8 h-8 rounded-xl flex items-center justify-center text-white text-xs shadow-lg shadow-indigo-500/20`}>
              <i className={`fa-solid ${app.icon || 'fa-microchip'}`}></i>
            </div>
            <div>
              <h3 className="text-[10px] font-black text-white uppercase tracking-widest leading-none">{app.name}</h3>
              <p className="text-[8px] text-indigo-400 font-bold uppercase tracking-widest mt-1">Virtual Runtime v2.5</p>
            </div>
          </div>
        </div>

        {isFullyReady && !error && (
          <div className="hidden md:flex bg-white/5 rounded-xl p-1 border border-white/10">
            <button 
              onClick={() => setViewMode('app')}
              className={`px-6 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'app' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
            >
              <i className="fa-solid fa-play mr-2"></i>Live App
            </button>
            <button 
              onClick={() => setViewMode('files')}
              className={`px-6 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'files' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}
            >
              <i className="fa-solid fa-folder-tree mr-2"></i>Source Files
            </button>
          </div>
        )}

        <div className="flex items-center gap-4">
           {isFullyReady && (
             <div className="flex items-center gap-2 px-4 py-1.5 bg-emerald-500/10 rounded-full border border-emerald-500/20">
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-ping"></span>
                <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Active</span>
             </div>
           )}
           <button onClick={onClose} className="w-10 h-10 rounded-xl bg-white/5 text-gray-400 hover:text-white hover:bg-rose-500 transition-all flex items-center justify-center">
              <i className="fa-solid fa-power-off text-sm"></i>
           </button>
        </div>
      </div>

      {/* Workspace */}
      <div className="flex-1 flex overflow-hidden relative">
        {/* Loading / Boot Screen */}
        {(!isFullyReady && !error) && (
          <div className="absolute inset-0 z-50 bg-[#050505] flex flex-col items-center justify-center p-12">
            <div className="w-full max-w-2xl space-y-12">
               <div className="flex items-end justify-between">
                  <div className="space-y-2">
                    <h2 className="text-4xl font-black text-white tracking-tighter uppercase leading-none">Executing Module</h2>
                    <p className="text-xs text-indigo-400 font-black uppercase tracking-[0.4em]">Sandbox Environment v2.5.0</p>
                  </div>
                  <div className="text-6xl font-black text-white/10 italic">{Math.round(bootStage)}%</div>
               </div>

               <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-500 shadow-[0_0_20px_rgba(79,70,229,0.5)]" style={{ width: `${bootStage}%` }}></div>
               </div>

               <div className="bg-black/40 rounded-3xl border border-white/5 p-8 font-mono text-[11px] h-72 overflow-y-auto space-y-3 scrollbar-hide">
                  {logs.map((log, i) => (
                    <div key={i} className="text-gray-500 animate-in fade-in slide-in-from-left-4">
                      <span className="text-indigo-500/50 mr-3">SYSTEM:</span> {log}
                    </div>
                  ))}
                  <div className="animate-pulse text-indigo-500">_</div>
               </div>
            </div>
          </div>
        )}

        {/* Error State */}
        {error && (
          <div className="absolute inset-0 z-[60] bg-[#050505] flex flex-col items-center justify-center p-8 text-center">
             <div className="w-20 h-20 rounded-full bg-rose-500/20 flex items-center justify-center text-rose-500 mb-6 text-4xl">
                <i className="fa-solid fa-triangle-exclamation"></i>
             </div>
             <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Execution Failed</h2>
             <p className="text-gray-500 max-w-md font-medium mb-8">{error}</p>
             <button onClick={onClose} className="px-10 py-4 bg-white text-black rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-rose-500 hover:text-white transition-all">
               Close Runtime
             </button>
          </div>
        )}

        {/* Live Viewport */}
        {isFullyReady && !error && (
          <div className="flex-1 flex flex-col">
            {viewMode === 'app' ? (
              <div className="flex-1 flex flex-col bg-white">
                 <div className="h-10 bg-gray-100 border-b flex items-center px-4 gap-6">
                    <div className="flex gap-4 text-gray-400">
                       <i className="fa-solid fa-chevron-left text-xs"></i>
                       <i className="fa-solid fa-chevron-right text-xs"></i>
                       <i className="fa-solid fa-rotate-right text-xs"></i>
                    </div>
                    <div className="flex-1 h-7 bg-white rounded-lg border border-gray-200 flex items-center px-4 gap-2">
                       <i className="fa-solid fa-shield-halved text-[9px] text-emerald-500"></i>
                       <span className="text-[10px] font-mono text-gray-500 truncate">{appUrl}</span>
                    </div>
                 </div>
                 <div className="flex-1 relative overflow-hidden">
                    {appUrl ? (
                      <iframe 
                        src={appUrl} 
                        className="w-full h-full border-none"
                        sandbox="allow-scripts allow-forms allow-modals allow-popups"
                        title={app.name}
                      />
                    ) : (
                      <div className="absolute inset-0 flex items-center justify-center bg-gray-50">
                         <p className="text-sm font-black text-gray-300 uppercase tracking-widest">No Live Content Rendered</p>
                      </div>
