            ) : (
              <div className="flex-1 bg-[#0a0a0a] p-12 overflow-y-auto">
                 <div className="max-w-5xl mx-auto space-y-10">
                    <div className="flex items-center justify-between border-b border-white/10 pb-8">
                       <div>
                         <h2 className="text-3xl font-black text-white tracking-tighter uppercase">Package Contents</h2>
                         <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.4em] mt-2">Virtual File System</p>
