import React, { useState, useEffect } from 'react';
import JSZip from 'jszip';
import { APPS } from '../constants';
import { AppItem } from '../types';

// Store session-based ZIP files (since localStorage is too small)
const ZIP_STORE = new Map<string, File>();

const LocalAppRunner: React.FC<{ app: AppItem; onClose: () => void; isDarkMode: boolean }> = ({ app, onClose, isDarkMode }) => {
  const [bootStage, setBootStage] = useState(0);
  const [logs, setLogs] = useState<string[]>([]);
  const [isFullyReady, setIsFullyReady] = useState(false);
  const [viewMode, setViewMode] = useState<'app' | 'files'>('app');
  const [appUrl, setAppUrl] = useState<string | null>(null);
  const [vfs, setVfs] = useState<{name: string, type: string}[]>([]);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const runSequence = async () => {
      setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Đang khởi tạo Sandbox...`]);

      try {
        if (app.url) {
          setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Chế độ URL: Đang kết nối...`]);
          setAppUrl(app.url);
          setBootStage(100);
          setIsFullyReady(true);
          return;
        }

        const file = ZIP_STORE.get(app.id);
        if (!file) throw new Error("Không tìm thấy tệp ZIP nguồn. Vui lòng tải lại tệp trong module Deploy.");

        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Đang giải nén: ${file.name}...`]);
        setBootStage(20);

        const zip = await JSZip.loadAsync(file);
        const assetMap = new Map<string, string>();
        const files: {name: string, type: string}[] = [];

        // Step 1: Extract all files and create a Virtual Asset Map
        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Đang xây dựng bản đồ tài nguyên ảo (VAM)...`]);

        const zipEntries: string[] = [];
        zip.forEach((path) => zipEntries.push(path));

        for (const path of zipEntries) {
          const entry = zip.file(path);
          if (entry && !entry.dir) {
            const blob = await entry.async("blob");
            // Determine MIME type based on extension
            const ext = path.split('.').pop()?.toLowerCase();
            let mimeType = 'application/octet-stream';
            if (ext === 'js') mimeType = 'application/javascript';
            else if (ext === 'css') mimeType = 'text/css';
            else if (ext === 'png') mimeType = 'image/png';
            else if (ext === 'jpg' || ext === 'jpeg') mimeType = 'image/jpeg';
            else if (ext === 'svg') mimeType = 'image/svg+xml';
            else if (ext === 'html') mimeType = 'text/html';

            const typedBlob = new Blob([blob], { type: mimeType });
            const url = URL.createObjectURL(typedBlob);
            assetMap.set(path, url);
            files.push({ name: path, type: 'file' });
          } else if (entry?.dir) {
            files.push({ name: path, type: 'dir' });
          }
        }
        setVfs(files);
        setBootStage(50);

        // Step 2: Identify Entry Point (index.html)
        let entryPath = zipEntries.find(p => p.toLowerCase() === "index.html" || p.toLowerCase().endsWith("/index.html"));

        if (!entryPath) {
          throw new Error("Không tìm thấy tệp 'index.html' trong gói ZIP. Vui lòng đảm bảo tệp này tồn tại ở thư mục gốc của gói.");
        }

        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Đã xác định entry point: ${entryPath}`]);

        // Step 3: Path Rewriting Engine
        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Đang thực hiện Path Rewriting cho index.html...`]);
        let htmlContent = await zip.file(entryPath)!.async("string");

        assetMap.forEach((blobUrl, originalPath) => {
          const fileNameOnly = originalPath.split('/').pop()!;
          const patterns = [
            `src=["']${originalPath}["']`,
            `src=["']\\.\\/${originalPath}["']`,
            `href=["']${originalPath}["']`,
            `href=["']\\.\\/${originalPath}["']`,
            `src=["']${fileNameOnly}["']`,
            `href=["']${fileNameOnly}["']`
          ];

          patterns.forEach(pattern => {
            const regex = new RegExp(pattern, 'g');
            const attr = pattern.startsWith('src') ? 'src' : 'href';
            htmlContent = htmlContent.replace(regex, `${attr}="${blobUrl}"`);
          });
        });

        const finalBlob = new Blob([htmlContent], { type: 'text/html' });
        setAppUrl(URL.createObjectURL(finalBlob));

        setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] Engine READY. Đang khởi chạy giao diện...`]);
        setBootStage(100);
        setTimeout(() => setIsFullyReady(true), 600);

      } catch (err: any) {
        setLogs(prev => [...prev, `[CRITICAL ERROR] ${err.message}`]);
        setError(err.message);
      }
    };

    runSequence();

    return () => {
      // Memory cleanup
      if (appUrl && appUrl.startsWith('blob:')) URL.revokeObjectURL(appUrl);
    };
  }, [app]);

  return (
    <div className="fixed inset-0 z-[300] bg-[#050505] flex flex-col animate-in fade-in duration-500 overflow-hidden">
      {/* Header OS-Style */}
      <div className="h-14 border-b border-white/10 flex items-center justify-between px-6 bg-black/80 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className="flex gap-2 mr-2">
            <button onClick={onClose} className="w-3.5 h-3.5 rounded-full bg-rose-500 hover:scale-110 transition-transform shadow-lg shadow-rose-500/20"></button>
            <div className="w-3.5 h-3.5 rounded-full bg-amber-500/10"></div>
            <div className="w-3.5 h-3.5 rounded-full bg-emerald-500/10"></div>
          </div>
          <div className="flex items-center gap-3 border-l border-white/10 pl-4">
            <div className={`${app.color} w-8 h-8 rounded-xl flex items-center justify-center text-white text-xs shadow-lg`}>
              <i className={`fa-solid ${app.icon || 'fa-rocket'}`}></i>
            </div>
            <div>
              <h3 className="text-[10px] font-black text-white uppercase tracking-widest leading-none">{app.name}</h3>
              <p className="text-[8px] text-indigo-400 font-bold uppercase tracking-widest mt-1">Virtual Hub Engine v3.0</p>
            </div>
          </div>
        </div>

        {isFullyReady && !error && (
          <div className="hidden md:flex bg-white/5 rounded-xl p-1 border border-white/10">
            <button onClick={() => setViewMode('app')} className={`px-6 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'app' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-gray-500 hover:text-white'}`}>
              <i className="fa-solid fa-desktop mr-2"></i>Ứng dụng
            </button>
            <button onClick={() => setViewMode('files')} className={`px-6 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${viewMode === 'files' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-gray-500 hover:text-white'}`}>
              <i className="fa-solid fa-folder-tree mr-2"></i>Tệp tin
            </button>
          </div>
        )}

        <div className="flex items-center gap-4">
           {isFullyReady && (
             <div className="flex items-center gap-2 px-4 py-1.5 bg-emerald-500/10 rounded-full border border-emerald-500/20">
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-ping"></span>
                <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Live</span>
             </div>
           )}
           <button onClick={onClose} className="w-10 h-10 rounded-xl bg-white/5 text-gray-400 hover:text-rose-500 transition-all flex items-center justify-center">
              <i className="fa-solid fa-power-off text-sm"></i>
           </button>
        </div>
      </div>

      {/* Main Container */}
      <div className="flex-1 relative bg-black">
        {(!isFullyReady && !error) && (
          <div className="absolute inset-0 flex flex-col items-center justify-center p-8">
            <div className="w-full max-w-lg space-y-6 text-center">
               <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400 mb-2">
                  <span>Initializing Sandbox Environment...</span>
                  <span>{bootStage}%</span>
               </div>
               <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden border border-white/5">
                 <div className="h-full bg-indigo-500 transition-all duration-500 shadow-[0_0_15px_rgba(99,102,241,0.5)]" style={{width: `${bootStage}%`}}></div>
               </div>
               <div className="bg-white/[0.02] border border-white/5 rounded-2xl p-6 font-mono text-[10px] text-left space-y-2 h-48 overflow-y-auto custom-scrollbar">
                  {logs.map((log, i) => (
                    <div key={i} className={log.includes('ERROR') ? 'text-rose-400' : 'text-indigo-300/60'}>
                      <span className="opacity-40 mr-2">{i+1}</span> {log}
                    </div>
                  ))}
               </div>
            </div>
          </div>
        )}

        {error && (
          <div className="absolute inset-0 flex items-center justify-center p-8 text-center">
            <div className="max-w-md space-y-6">
              <div className="w-20 h-20 bg-rose-500/10 rounded-3xl flex items-center justify-center text-rose-500 text-3xl mx-auto shadow-2xl shadow-rose-500/20">
                <i className="fa-solid fa-triangle-exclamation"></i>
              </div>
              <h2 className="text-xl font-black text-white uppercase tracking-widest">System Failure</h2>
              <p className="text-sm text-gray-400 font-medium leading-relaxed">{error}</p>
              <button onClick={onClose} className="px-8 py-3 bg-white text-black rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all">
                Terminate Sandbox
              </button>
            </div>
          </div>
        )}

        {isFullyReady && !error && (
          <div className="w-full h-full">
            {viewMode === 'app' ? (
              <iframe 
                src={appUrl || ''} 
                className="w-full h-full border-none bg-white"
                title={app.name}
              />
            ) : (
              <div className="p-8 h-full overflow-y-auto bg-[#0a0a0a]">
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {vfs.map((file, i) => (
                    <div key={i} className="p-4 bg-white/5 border border-white/5 rounded-2xl flex items-center gap-4">
                      <div className="w-10 h-10 bg-indigo-500/10 rounded-xl flex items-center justify-center text-indigo-400">
                        <i className={`fa-solid ${file.type === 'dir' ? 'fa-folder' : 'fa-file-code'}`}></i>
                      </div>
                      <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest truncate">{file.name}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

