const LocalAppRunner: React.FC<{ app: AppItem; onClose: () => void; isDarkMode: boolean }> = ({ app, onClose, isDarkMode }) => {
  const [bootStage, setBootStage] = useState(0);
  const [isFullyReady, setIsFullyReady] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => {
      setBootStage(prev => {
        if (prev >= 100) {
          clearInterval(timer);
          setIsFullyReady(true);
          return 100;
        }
        return prev + 10;
      });
    }, 100);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="fixed inset-0 z-[300] bg-[#050505] flex flex-col animate-in fade-in duration-500 overflow-hidden">
      <div className="h-14 border-b border-white/10 flex items-center justify-between px-6 bg-black/80 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className="flex gap-2 mr-2">
            <button onClick={onClose} className="w-3.5 h-3.5 rounded-full bg-rose-500 hover:scale-110 transition-transform shadow-lg shadow-rose-500/20"></button>
            <div className="w-3.5 h-3.5 rounded-full bg-amber-500/10"></div>
            <div className="w-3.5 h-3.5 rounded-full bg-emerald-500/10"></div>
          </div>
          <div className="flex items-center gap-3 border-l border-white/10 pl-4">
            <div className={`${app.color} w-8 h-8 rounded-xl flex items-center justify-center text-white text-xs shadow-lg`}>
              <i className={`fa-solid ${app.icon || 'fa-rocket'}`}></i>
            </div>
            <div>
              <h3 className="text-[10px] font-black text-white uppercase tracking-widest leading-none">{app.name}</h3>
              <p className="text-[8px] text-indigo-400 font-bold uppercase tracking-widest mt-1">External Web Access</p>
            </div>
          </div>
        </div>
        <button onClick={onClose} className="w-10 h-10 rounded-xl bg-white/5 text-gray-400 hover:text-rose-500 transition-all flex items-center justify-center">
          <i className="fa-solid fa-power-off text-sm"></i>
        </button>
      </div>

      <div className="flex-1 relative bg-black">
        {!isFullyReady ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center p-8">
            <div className="w-full max-w-lg space-y-6 text-center">
               <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400 mb-2">
                  <span>Connecting to source...</span>
                  <span>{bootStage}%</span>
               </div>
               <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden border border-white/5">
                 <div className="h-full bg-indigo-500 transition-all duration-300" style={{width: `${bootStage}%`}}></div>
               </div>
            </div>
          </div>
        ) : (
          <iframe 
            src={app.url} 
            className="w-full h-full border-none bg-white"
            title={app.name}
          />
        )}
      </div>
    </div>
  );
};

const Dashboard: React.FC<{ isDarkMode: boolean; user: User }> = ({ isDarkMode, user }) => {
  const [selectedApp, setSelectedApp] = useState<AppItem | null>(null);
  const [customApps, setCustomApps] = useState<AppItem[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [search, setSearch] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('tig_hub_custom_web_apps');
    if (saved) setCustomApps(JSON.parse(saved));
  }, []);

  const handleDeploy = (e: React.FormEvent) => {
    e.preventDefault();
    const form = e.target as any;
    const newApp: AppItem = {
      id: Date.now().toString(),
      name: form.appName.value,
      description: form.appDesc.value,
      url: form.appUrl.value,
      icon: 'fa-globe',
      category: 'External Site',
      color: 'bg-indigo-600',
      developer: user.name
    };

    const updated = [newApp, ...customApps];
    setCustomApps(updated);
    localStorage.setItem('tig_hub_custom_web_apps', JSON.stringify(updated));
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Gỡ bỏ trang web này?')) {
      const updated = customApps.filter(a => a.id !== id);
      setCustomApps(updated);
      localStorage.setItem('tig_hub_custom_web_apps', JSON.stringify(updated));
    }
  };

  const allApps = [...customApps, ...APPS];
  const filteredApps = allApps.filter(app => 
    app.name.toLowerCase().includes(search.toLowerCase()) || 
    (app.developer || '').toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
