        <div className="flex gap-4">
          <div className="relative">
            <i className="fa-solid fa-magnifying-glass absolute left-4 top-1/2 -translate-y-1/2 text-gray-500"></i>
            <input 
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="Search websites..."
              className={`pl-12 pr-6 py-4 rounded-2xl outline-none border transition-all font-bold text-sm w-64 ${isDarkMode ? 'bg-white/5 border-white/10 text-white focus:border-indigo-500' : 'bg-gray-100 border-gray-200'}`}
