      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredApps.map((app) => (
          <div 
            key={app.id} 
            className={`group p-8 rounded-[2.5rem] border transition-all hover:-translate-y-2 relative ${
              isDarkMode ? 'bg-[#0a0a0a] border-white/5 hover:border-indigo-500/50 hover:shadow-2xl hover:shadow-indigo-500/10' : 'bg-white border-gray-100 hover:border-black hover:shadow-2xl'
            }`}
          >
            {customApps.some(a => a.id === app.id) && (
              <button 
                onClick={(e) => { e.stopPropagation(); handleDelete(app.id); }}
