import { GoogleGenAI, Type } from "@google/genai";
import { Presentation } from "../types";

/**
 * Helper to initialize GoogleGenAI with the required API key from environment.
 */
const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a full presentation structure including slides using Gemini 3 Pro.
 * @param topic The topic of the presentation.
 * @param style The visual and content style (e.g., Professional, Futuristic).
 * @returns A promise that resolves to a Presentation object.
 */
export const generatePresentation = async (topic: string, style: string): Promise<Presentation> => {
  const ai = getAi();

  // Use gemini-3-pro-preview for complex reasoning and structure generation.
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Generate a professional and detailed presentation outline for the topic: "${topic}". 
    The style of the presentation should be "${style}". 
    Provide exactly 5 to 7 slides. 
    Each slide must have a title, 3-5 bullet points of content, and detailed speaker notes.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: {
            type: Type.STRING,
            description: "The main title of the presentation."
          },
          description: {
            type: Type.STRING,
            description: "A brief summary of the presentation."
          },
          slides: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: {
                  type: Type.STRING,
                  description: "A unique identifier for the slide."
                },
                title: {
                  type: Type.STRING,
                  description: "The title of the slide."
                },
                content: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING },
                  description: "Bullet points for the slide content."
                },
                speakerNotes: {
                  type: Type.STRING,
                  description: "Detailed notes for the presenter."
                }
              },
              required: ["id", "title", "content", "speakerNotes"]
            }
          }
        },
        required: ["title", "description", "slides"]
      }
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  const parsedData = JSON.parse(text);

  return {
    ...parsedData,
    id: `pres-${Date.now()}`,
    createdAt: new Date().toISOString()
  };
};

/**
 * Generates an AI image for a presentation slide using Gemini 2.5 Flash Image.
 * @param title The title of the slide.
 * @param content The content description of the slide.
 * @returns A promise that resolves to a base64 encoded image string.
 */
export const generateImageForSlide = async (title: string, content: string): Promise<string> => {
  const ai = getAi();

  // Use gemini-2.5-flash-image for general image generation tasks.
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          text: `Create a cinematic, high-quality, professional presentation background for a slide titled "${title}". 
          The slide discusses: ${content}. 
          The image should be abstract or representative, without any text, and visually stunning.`,
        },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  // Iterate through parts to find the image part
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        const base64Data = part.inlineData.data;
        const mimeType = part.inlineData.mimeType || 'image/png';
        return `data:${mimeType};base64,${base64Data}`;
      }
    }
  }

  throw new Error("No image was generated by the AI.");
};

